import React, { FC, useContext, useEffect, useState } from 'react'
import { getCurrentTab } from '../../api/browser'
import { Col, Row } from 'react-bootstrap'
import styles from './Metrics.module.scss';
import { AppStorage } from '../../helpers/AppStorage'
import { MetaStorage } from '../../helpers/MetaStorage'
import MBCard from '../Common/MBCard/MBCard'
import MBAlert from '../Common/MBAlert/MBAlert'
import MBPremium from '../Common/MBPremium/MBPremium'
import { AppContext } from '../../config/state'
import { ApiServiceV2, ApiServiceV2_Scope } from '../../api/api_v2'
import MBQuota from '../Common/MBQuota/MBQuota'
import MBErrorMessage from '../Common/MBErrorMessage/MBErrorMessage'

interface MetricsProps {
  is_pro?: boolean
}

const resourceTabs = getCurrentTab()

const Metrics: FC<MetricsProps> = () => {
  const appStorage = new AppStorage()
  const metaStorage = new MetaStorage()
  const {data} = useContext(AppContext)
  const [currentTab] = resourceTabs.read()
  const isProPlan = data?.is_pro
  const [error, setError] = useState('')

  const [results, setResults] = useState<any>([])

  useEffect(() => {
    const api2 = new ApiServiceV2(data?.token)
    const url = metaStorage.getUrlNoQuery(currentTab.url)
    api2.overview_cache(url, ApiServiceV2_Scope.Url).then((metrics) => {
      setError('')
      setResults(metrics)
    }, (err) => {
      setError(err)
    })
  }, [])

  return (
    <div className={styles.Metrics} data-testid="Metrics">
      <h1>Link Metrics <MBPremium/></h1>
      <MBAlert/>
      <MBQuota/>
      {error && (<MBErrorMessage message={error}/>)}
      {data?.is_pro && results?.page_extended?.spam_score && (
        <h3 style={{ marginBottom: "20px", marginTop: "-10px"}}>Spam Score: {results?.page_extended?.spam_score}%</h3>
      )}
      <Row>
        <Col xs={6}>
          <h3>Page Metrics</h3>
        </Col>
        <Col xs={6}>
          <h3>Domain Metrics</h3>
        </Col>
        <Col xs={6}>
          <MBCard cardClass={styles.card}
                  cardTitle={"Page Authority"}
                  cardTooltip={metaStorage.pageAuhorityTooltip}
                  cardValue={results?.page?.page_authority}
                  showPie={data?.token ? true : false}
                  isBlur={!data?.token ? true : false}
                  url={metaStorage.buildMetricsLink(currentTab.url, 'page')}
          />
        </Col>
        <Col xs={6}>
          <MBCard cardClass={styles.card}
                  cardTitle={metaStorage.domainAuthorityName}
                  cardTooltip={metaStorage.domainAuthorityTooltip}
                  cardValue={results?.domain?.domain_authority}
                  showPie={data?.token ? true : false}
                  isBlur={!data?.token ? true : false}
                  url={metaStorage.buildMetricsLink(currentTab.url, 'domain')}
          />
        </Col>
        <Col xs={6}>
          <MBCard cardClass={styles.card}
                  cardTitle={"Linking Domains"}
                  cardTooltip={metaStorage.linkingDomainsTooltip}
                  cardValue={results?.page_extended?.linking_domains_count}
                  showPie={false}
                  isBlur={!isProPlan}
                  url={metaStorage.buildMetricsLink(currentTab.url, 'page')}
          />
        </Col>
        <Col xs={6}>
          <MBCard cardClass={styles.card}
                  cardTitle={"Linking Domains"}
                  cardTooltip={metaStorage.linkingDomainsTooltip}
                  cardValue={results?.domain_extended?.linking_domains_count}
                  showPie={false}
                  isBlur={!isProPlan}
                  url={metaStorage.buildMetricsLink(currentTab.url, 'domain')}
          />
        </Col>
        <Col xs={6}>
          <MBCard cardClass={styles.card}
                  cardTitle={"Inbound Links"}
                  cardTooltip={metaStorage.inboundLinksTooltip}
                  cardValue={results?.page?.linking_pages_count}
                  showPie={false}
                  isBlur={!isProPlan}
                  url={metaStorage.buildMetricsLink(currentTab.url, 'page')}
          />
        </Col>
        <Col xs={6}>
          <MBCard cardClass={styles.card}
                  cardTitle={"Inbound Links"}
                  cardTooltip={metaStorage.inboundLinksTooltip}
                  cardValue={results?.domain_extended?.linking_pages_count}
                  showPie={false}
                  isBlur={!isProPlan}
                  url={metaStorage.buildMetricsLink(currentTab.url, 'domain')}
          />
        </Col>
      </Row>
    </div>
  )
}

export default Metrics