import React, { FC, useContext } from 'react'
import { PieChart } from '@mui/x-charts'
import { AppContext } from '../../../config/state'
import { EventStorage } from '../../../helpers/EventStorage'

interface MBPieProps {
  size: number
  value: number | null,
  url?: string
}

const MBPie: FC<MBPieProps> = (props) => {
  const event = new EventStorage()
  const {data, } = useContext(AppContext)

  const pieClick = () => {
    if (props.url) {
      event.openLink(props.url)
    }
  }

  /**
   * Build Pie diagram
   * @param size
   * @param value
   */
  const buildPie = (size: number, value: number | null) => {
    const sizeInner = size - 12
    const angle = value ?? 0

    // Depending on theme switch pie color
    let color = '#0077BB'
    let back = '#bbbbbb'
    if (data?.is_dark) {
      color = '#4DBEEB'
      back = '#0F3755'
    }

    return (
      <span className={"main-cursor"} onClick={pieClick}>
        <PieChart
          series={[
            {
              data: [
                { value: angle, color: color },
                { value: 100 - angle, color: back },
              ],
              innerRadius: sizeInner,
              outerRadius: size,
              paddingAngle: 0,
              cx: size,
              cy: size,
            }
          ]}
          width={size*2 + 10}
          height={size*2 + 10}
          slotProps={{
            legend: { hidden: true },
          }}
          tooltip={{trigger: 'none'}}
        />
      </span>
    )
  }

  return (
    buildPie(props.size, props.value)
  )
}

export default MBPie;
