import React from 'react';
import ReactDOM from 'react-dom/client';
import './index.css';
import App from './App';
import reportWebVitals from './reportWebVitals';
import { UserContextProvider } from '../config/state-provider'
import { BrowserRouter } from 'react-router-dom'
import { LocalStorage } from '../helpers/LocalStorage'

const root = ReactDOM.createRoot(
  document.getElementById('root') as HTMLElement
);

let values
const ls = new LocalStorage()

ls.get('config').then((res: any) => {
  const initState = {
    token: res?.token,
    toolbar: res?.toolbar,
    serp: res?.serp,
    places: res?.places,
    is_dark: res?.theme,
    dock: res?.dock,
    avatar: res?.avatar,
    user: res?.user,
    is_pro: res?.is_pro,
    email: res?.email,
    block: res?.block,
    da_mode: res?.da_mode,
    quota_max: res?.quota_max,
    quota_current: res?.quota_current,
    period_start: res?.period_start,
    period_reset: res?.period_reset,
    quota_k_max: res?.quota_k_max,
    quota_k_current: res?.quota_k_current,
    keyword: res?.keyword,
    keywordhighlight: res?.keywordhighlight,
    followed: res?.followed,
    nofollow: res?.nofollow,
    external: res?.external,
    internal: res?.internal
  }
  values = {data: initState}

  root.render(
    <React.StrictMode>
      <UserContextProvider initial={values}>
        <BrowserRouter>
          <App />
        </BrowserRouter>
      </UserContextProvider>
    </React.StrictMode>
  );

  // If you want to start measuring performance in your app, pass a function
  // to log results (for example: reportWebVitals(console.log))
  // or send to an analytics endpoint. Learn more: https://bit.ly/CRA-vitals
  reportWebVitals();
}, (err) => {
  const initState = {is_dark: false, toolbar: false, serp: false, dock: 'top'}
  ls.push('config', initState)
  values = {data: initState}

  root.render(
    <React.StrictMode>
      <UserContextProvider initial={values}>
        <BrowserRouter>
          <App />
        </BrowserRouter>
      </UserContextProvider>
    </React.StrictMode>
  );

  // If you want to start measuring performance in your app, pass a function
  // to log results (for example: reportWebVitals(console.log))
  // or send to an analytics endpoint. Learn more: https://bit.ly/CRA-vitals
  reportWebVitals();
})