import React, { FC, useContext, useState } from 'react'
import styles from './MBGrader.module.scss';
import MBAlert from '../MBAlert/MBAlert'
import Grid from '@mui/material/Unstable_Grid2'
import { Button, FormControl, TextField } from '@mui/material'
import { ApiServiceV2, ApiServiceV2_Scope } from '../../../api/api_v2'
import { AppStorage } from '../../../helpers/AppStorage'
import { getCurrentTab } from '../../../api/browser'
// import { ReactJSXElement } from '@emotion/react/types/jsx-namespace'
import { AppContext } from '../../../config/state'
import { MetaStorage } from '../../../helpers/MetaStorage'
import MBErrorMessage from '../MBErrorMessage/MBErrorMessage'
import MBQuota from '../MBQuota/MBQuota'

interface MBGraderProps {
  content: JSX.Element[]
  description?: string
}

const resourceTabs = getCurrentTab()

const MBGrader: FC<MBGraderProps> = (props) => {
  const metaStorage = new MetaStorage()
  const appStorage = new AppStorage()
  const {data, updateState} = useContext(AppContext)
  const [currentTab] = resourceTabs.read()
  const disabled = !data?.is_pro
  const [error, setError] = useState('')

  const [keyword, setKeyword] = useState(appStorage.getCoreTab('summaryKeyword', currentTab.id))
  const [keywordErr, setKeywordErr] = useState('')
  const [keywordsGrid, updateKeywordsGrid] = useState<any>(
    data?.is_pro ? appStorage.getCoreTabJson('summaryGrid', currentTab.id) : []
  )

  /**
   * Analyze provided keyword
   */
  const optimize = () => {
    // Set initial error values to empty
    let isErr = false
    setKeywordErr('')
    if ('' === keyword) {
      setKeywordErr('error-highlight')
      isErr = true
    }
    if (isErr) return

    const service = new ApiServiceV2(data?.token)
    appStorage.setCoreTab('summaryKeyword', keyword, currentTab.id)
    service.grader_cache(keyword, currentTab.url, ApiServiceV2_Scope.Url).then( (res) => {
      setError('')
      appStorage.setCoreTab('summaryGrid', JSON.stringify(res), currentTab.id)
      updateKeywordsGrid(res)
      if (data) {
        data.action = 'grader'
        updateState({data: data})
      }
    }, (err) => {
      setError(err)
      appStorage.setCoreTab('summaryGrid', JSON.stringify(''), currentTab.id)
      updateKeywordsGrid(undefined)
      if (data) {
        data.action = 'grader'
        updateState({data: data})
      }
    })
  }

  /**
   * Main template
   */
  return (
    <div className={styles.MBGrader} data-testid="MBGrader">
      <MBAlert href={"https://moz.com/products/pro/pricing?utm_source=mozbar_v4&utm_medium=mozbar&utm_campaign=premium_new_signup&utm_content={tab-name}"}
               message={(<><strong>Get Mozbar Premium</strong> Available with Moz Pro</>)} button={"Sign Up"}
               href_token={"https://moz.com/products/pro/pricing?utm_source=mozbar_v4&utm_medium=mozbar&utm_campaign=premium_new_signup&utm_content=page-optimization"}
               message_token={(<><strong>Get Mozbar Premium</strong> Available with Moz Pro</>)} button_token={"Upgrade"}/>
      <MBQuota/>
      <p>{props.description ? props.description : "Get a handle on optimizing your page with our On-Page Grader tool, also available in Moz Pro. Enter a keyword to see your page score. We will show you how to optimize the page and prioritize issues."}</p>
      {error && (<MBErrorMessage message={"There was a problem loading this page. Please make sure the page is loading properly and that our user-agent, rogerbot, is not blocked from accessing this page."}/>)}
      <Grid container spacing={2} className={styles.gridContainer}>
        <Grid xs={9} justifyContent="center" alignItems="center">
          <div className={'inputContainer'}>
            <div className={['input-label', keywordErr].join(' ')}>Search keyword</div>
            <FormControl sx={{ m: 1, minWidth: 180 }} size={'small'} fullWidth>
              <TextField
                sx={{ borderWidth: '2px' }}
                size={'small'}
                value={keyword}
                inputProps={{ 'aria-label': 'Without label', endAdornment: <Button/> }}
                onChange={(ev: any) => {setKeyword(ev.target.value)}}
              />
            </FormControl>
          </div>
        </Grid>
        <Grid xs={3} justifyContent="center" alignItems="center">
          <div className={'button-section-grid'}>
            <Button variant="contained" onClick={optimize} size="small" fullWidth disabled={disabled}>Analyze</Button>
          </div>
        </Grid>
      </Grid>
      {keywordsGrid && data?.is_pro && (
        <div className="mozbar-card-main">
          <div className={styles.contentheader}>
            {keywordsGrid.title && (<>
                <div className={styles.pagetitle}>Page Title: {keywordsGrid.title}</div>
                <a className={styles.pagelink}>{keywordsGrid.final_url}</a>
              </>
            )}
          </div>
          {props.content}
        </div>
      )}
    </div>
  );
}

export default MBGrader;
