import React, { FC, useContext, useEffect, useState } from 'react'
import styles from './Links.module.scss';
import { getCurrentTab } from '../../api/browser'
import { Button, Checkbox, Chip, FormControl, FormControlLabel, Stack, Switch, TextField } from '@mui/material'
import { EventStorage } from '../../helpers/EventStorage'
import { AppStorage } from '../../helpers/AppStorage'
import { AppContext } from '../../config/state'
import { LocalStorage } from '../../helpers/LocalStorage'

const resourceTabs = getCurrentTab()

const Links: FC = () => {
  const [currentTab] = resourceTabs.read()
  const eventStorage = new EventStorage()
  const app = new AppStorage()
  const ls = new LocalStorage()
  const {data, updateState} = useContext(AppContext)

  const [linkStates, setLinkStates] = useState<any>({
    keyword: data?.keyword,
    keywordhighlight: data?.keywordhighlight,
    followed: data?.followed,
    nofollow: data?.nofollow,
    external: data?.external,
    internal: data?.internal,
  })

  const [keywordErr, setKeywordErr] = useState('')
  const [keywordCount, setKeywordCount] = useState('')

  useEffect(() => {
    const messageListener = (response: any) => {
      if (response.type === eventStorage.SOURCE_EXTENSION && response.message === 'countwords') {
        setKeywordCount(response.count)
      }
    }
    chrome.runtime.onMessage.addListener(messageListener)
  }, [])

  const findKeyword = () => {
    eventStorage.sendTabMessage(currentTab?.id, eventStorage.buildMessage(
      eventStorage.SOURCE_CONTENT, eventStorage.SOURCE_EXTENSION, 'countwords',
      { keyword: linkStates.keyword }
    ))
  }

  const changeLink = (value: boolean, type: string) => {
    setLinkStates((prev: any) => ({ ...prev, [type]: value }))
    // app.setCore(type, value.toString())
    updateState(app.prepareState(data, type, value))
    ls.push('config', {[type]: value})
    
    const message = type === 'keywordhighlight'
      ? { type, value, keyword: linkStates.keyword }
      : { type, value }
    
    eventStorage.sendTabMessage(currentTab?.id, eventStorage.buildMessage(
      eventStorage.SOURCE_CONTENT, eventStorage.SOURCE_EXTENSION, 'highlight', message
    ))
  }

  const searchResults: any[] = []
  if (keywordCount.toString().length>0) {
    if (Number(keywordCount)>0)
      searchResults.push(<div>{keywordCount} {Number(keywordCount)>1 ? 'results' : 'result'}</div>)
    else
      searchResults.push(<div>No results</div>)
  } else {
    searchResults.push(<></>)
  }



  function renderLinkTypes() {
    const linkTypes = [
      { key: 'followed', label: 'Followed', description: 'A link that search engines recognize and count towards improving the linked page\'s visibility in search results.' },
      { key: 'nofollow', label: 'No-Follow', description: 'A link that search engines see but do not count towards improving the linked page\'s visibility in search results.' },
      { key: 'external', label: 'External', description: 'A hyperlink that points to a page on a different website, which can improve that page\'s visibility and traffic.' },
      { key: 'internal', label: 'Internal', description: 'A link that points to another page within the same website, helping with navigation and SEO.' },
    ]

    return linkTypes.map(({ key, label, description }) => (
      <div key={key}>
        <p className={styles.control}>
          <FormControlLabel
            control={
              <Switch
                inputProps={{ 'aria-label': label }}
                checked={linkStates[key] === true}
                onChange={(ev) => changeLink(ev.target.checked, key)}
              />
            }
            label={label}
          />
          <Chip label={`${label} link`} sx={{ ...chipStyle, background: `var(--link-${key})` }} />
        </p>
        <p className={styles.description}>{description}</p>
      </div>
    ))
  }

  function renderKeywordSearch() {
    return (
      <>
        <p className={styles.bold} style={{marginTop: "15px"}}>Highlight keywords</p>
        <div className={'inputContainer'} style={{paddingTop: "0px"}}>
          <div className={["input-label", keywordErr].join(' ')}>Search keyword</div>
          <FormControl sx={{ m: 1, minWidth: 180 }} size={"small"} fullWidth>
            <TextField
              sx={{ borderWidth: "2px" }}
              size={"small"}
              value={linkStates.keyword}
              inputProps={{ 'aria-label': 'Without label', endAdornment: <Button/> }}
              onChange={(ev: any) => {
                setLinkStates((prev: any) => ({ ...prev, keyword: ev.target.value, keywordhighlight: 'false' }))
                updateState(app.prepareState(data, 'keyword', ev.target.value))
                ls.push('config', {'keyword': ev.target.value})
                updateState(app.prepareState(data, 'keywordhighlight', false))
                ls.push('config', {'keyword': false})
              }}
            />
          </FormControl>
        </div>

        <div className='row' style={{marginTop: "5px"}}>
          <div className='col-7'>
            <FormControlLabel control={<Checkbox inputProps={{ 'aria-label': 'Highlight keyword' }} checked={linkStates.keywordhighlight=='true'} onChange={
              (ev) => changeLink(ev.target.checked, 'keywordhighlight')
            }/>} label="Highlight keyword search results"/>
            <div className={[styles.buttonsectionlinks, "button-section"].join(' ')}>
              <Stack spacing={1} direction={"row"} alignItems={"center"} justifyContent={"flex-start"}>
                <Button variant="contained" onClick={findKeyword} size="small" sx={{fontSize: "13px"}}>Find keyword</Button>
                {searchResults}
              </Stack>
            </div>
          </div>
          <div className='col-5'>
            <Chip label="Highlighted keyword" sx={{ ...chipStyle, background: "var(--link-highlight)" }}/>
          </div>
        </div>
      </>
    )
  }

  const chipStyle = {float: "right", borderRadius: "3px", color: "#002F50", fontSize: "13px"}
  return (
    <div className={styles.Links} data-testid="Links">
      <h1>Highlight Links</h1>
      <p className={styles.bold}>Choose what type of links to highlight</p>
      {renderLinkTypes()}
      {renderKeywordSearch()}
    </div>
  )
}

export default Links;
