import React, { FC, useEffect, useState } from 'react'
import styles from './MBBox.module.scss';
import { Col, Row } from 'react-bootstrap'
import { CopyAllOutlined, ExpandLess, ExpandMore, UnfoldMore } from '@mui/icons-material'
import { Button, Collapse, Stack } from '@mui/material'

interface MBBoxProps {
  item: any
  copy?: boolean
  collapse_enabled?: boolean
  expanded?: boolean
  copyText?: string,
  showExpand?: boolean
  showExpandFunc?: any
}

const MBBox: FC<MBBoxProps> = (props) => {
  const [expanded, setExpanded] = useState<boolean>(props.expanded !== undefined ? props.expanded : false)
  const [expandedText, setExpandedText] = useState<string>('Expand All')

  useEffect(() => {
     if (props.expanded!==undefined)
      setExpanded(props.expanded)
  }, [props])

  /**
   * Copy data to the clipboard
   */
  const copy = () => {
    if (props.copyText) {
      navigator.clipboard.writeText(props.copyText)
    }
    else if (props.item.copyText) {
      navigator.clipboard.writeText(props.item.copyText)
    }
    else if (Array.isArray(props.item?.content)) {
      let data = ''
      props.item?.content.forEach((item: any) => {
        data += item.props?.children + "\n"
      })
      navigator.clipboard.writeText(data)
    } else {
      navigator.clipboard.writeText(props.item?.content)
    }
  }

  /**
   * Main template
   */
  return (
    <div className={styles.MBBox}>
      <div className={styles.boxinfo}>
        <Row>
          <Col xs={5} className={styles.title}>
            <Stack alignItems="center" direction="row" spacing={2} justifyContent={"flex-start"} justifyItems={"center"}
                   onClick={(e) => setExpanded(!expanded)}>
              {props.collapse_enabled && (
                <div style={{cursor: "pointer"}}>
                  {expanded ? <ExpandLess/> : <ExpandMore/>}
                </div>
              )}
              <div style={{cursor: "pointer"}}>{props.item?.name}</div>
            </Stack>
          </Col>
          <Col xs={7} className={styles.secondary}>
            <Stack alignItems="right" direction={"column"} spacing={2} justifyContent={"flex-end"} justifyItems={"center"}>
              <div>
                {props?.showExpand && (
                  <Button color="inherit" size="small"
                          onClick={() => {
                            props.showExpandFunc()
                            setExpandedText(expandedText == 'Expand All' ? 'Collapse All' : 'Expand All')
                          }}
                          sx={{textTransform: "none", fontWeight: "700", fontSize: "14px", marginRight: "10px"}}
                          variant={"outlined"} startIcon={<UnfoldMore/>}>
                    {expandedText}
                  </Button>
                )}
                {props?.copy && props.item?.content && (
                  <Button color="inherit" size="small"
                          onClick={() => {copy()}}
                          sx={{textTransform: "none", fontWeight: "700", fontSize: "14px"}}
                          variant={"outlined"} startIcon={<CopyAllOutlined/>}>
                    Copy
                  </Button>
                )}
              </div>
              <div style={{marginTop: "5px"}}>{props.item?.secondary}</div>
            </Stack>
          </Col>
          <Col xs={12} className={styles.content}>
            {props.collapse_enabled && (
              <Collapse in={expanded} timeout="auto" unmountOnExit>
                <div style={{marginTop: "10px"}}>
                  {props.item?.content}
                </div>
              </Collapse>
            )}
            {!props.collapse_enabled && (
              <div style={{marginTop: "10px"}}>{props.item?.content}</div>
            )}
          </Col>
        </Row>
      </div>
    </div>
  )
}

export default MBBox;
