import React, { FC, useContext, useState, useEffect } from 'react'
import styles from './Hurting.module.scss'
import { AppStorage } from '../../helpers/AppStorage'
import MBGrader from '../Common/MBGrader/MBGrader'
import { ApiHelper } from '../../api/helper'
import MBFactors from '../Common/MBFactors/MBFactors'
import { getCurrentTab } from '../../api/browser'
import { AppContext } from '../../config/state'
import MBPremium from '../Common/MBPremium/MBPremium'

const resourceTabs = getCurrentTab()

const Hurting: FC = () => {
  const appStorage = new AppStorage()
  const [currentTab] = resourceTabs.read()
  const { data, updateState } = useContext(AppContext)

  const [keywordsGrid, setKeywordsGrid] = useState(() =>
    appStorage.getCoreTabJson('summaryGrid', currentTab.id)
  )

  useEffect(() => {
    if (data?.action === 'grader') {
      updateState({ data: { ...data, action: '' } })
      setKeywordsGrid(appStorage.getCoreTabJson('summaryGrid', currentTab.id))
    }
  }, [data, updateState, appStorage, currentTab.id])

  const factors = keywordsGrid ? new ApiHelper().factorsHurting(keywordsGrid.marks) : []

  return (
    <div className={styles.Hurting} data-testid="Hurting">
      <h1>Hurting Factors <MBPremium /></h1>
      <MBGrader description={"Enter a keyword below to see which on-page factors might hurt this page’s overall score."} content={[
        <MBFactors factors={factors} type="Factors hurting your score"/>
      ]} />
    </div>
  )
}

export default Hurting