import React, { FC, useContext, useState, useMemo } from 'react'
import styles from './DomainOverview.module.scss';
import {
  Button,
  FormControl,
  ListItemIcon, ListItemText,
  MenuItem,
  Select, Stack
} from '@mui/material'
import { Col, Row } from 'react-bootstrap'
import MBAlert from '../Common/MBAlert/MBAlert'
import Grid from '@mui/material/Unstable_Grid2'
import { MetaStorage } from '../../helpers/MetaStorage'
import { AppStorage } from '../../helpers/AppStorage'
import { ApiServiceV2, ApiServiceV2_Scope } from '../../api/api_v2'
import { getCurrentTab } from '../../api/browser'
import MBCard from '../Common/MBCard/MBCard'
import MBPremium from '../Common/MBPremium/MBPremium'
import { AppContext } from '../../config/state'
import { FlagIcon, FlagIconCode } from 'react-flag-kit'
import MBMozAI from '../Common/MBMozAI/MBMozAI'
import MBQuota from '../Common/MBQuota/MBQuota'
import MBErrorMessage from '../Common/MBErrorMessage/MBErrorMessage'

const resourceTabs = getCurrentTab()

const DomainOverview: FC = () => {
  const appStorage = useMemo(() => new AppStorage(), [])
  const metaStorage = useMemo(() => new MetaStorage(), [])
  const {data} = useContext(AppContext)
  const [currentTab] = resourceTabs.read()
  const [domainOverview, setDomainOverview] = useState(() =>
    data?.is_pro ? appStorage.getCoreTabJson('domainOverview', currentTab.id) : []
  )
  const [domain, setDomain] = useState(() => appStorage.getCoreTab('domainOverviewDomain', currentTab.id))
  const [country, setCountry] = useState(() => appStorage.getCoreTab('domainOverviewCountry', currentTab.id))
  const [domainErr, setDomainErr] = useState('')
  const [countryErr, setCountryErr] = useState('')
  const [error, setError] = useState('')
  const domains = useMemo(() => metaStorage.domains(), [])
  const countries = useMemo(() => metaStorage.locales(), [])

  const domainsData = useMemo(() => domains.map(d => (
    <MenuItem key={d.key} value={d.key.toLowerCase()}>{d.name}</MenuItem>
  )), [domains])

  const countriesData = useMemo(() => Object.entries(countries).map(([key, c]) => (
    <MenuItem key={key} value={c.locale}>
      <Stack direction="row" spacing={0} alignItems="center" sx={{height: "20px !important"}}>
        <ListItemIcon sx={{minWidth: "30px"}}>
          <FlagIcon code={c.icon as FlagIconCode} width="22px" height="16px"/>
        </ListItemIcon>
        <ListItemText primary={c.name} sx={{marginTop: "8px"}} />
      </Stack>
    </MenuItem>
  )), [countries])

  /**
   * Analyze provided keywords
   */
  const optimize = async () => {
    setDomainErr('')
    if (!domain) setDomainErr('error-highlight')
    if (!domain) return
    appStorage.setCoreTab('domainOverviewDomain', domain, currentTab.id)

    try {
      const service = new ApiServiceV2()
      service.setToken(data?.token)
      let url = currentTab.url
      if (domain == ApiServiceV2_Scope.Domain) {
        url = metaStorage.getDomain(url)
      } else if (domain == ApiServiceV2_Scope.Subdomain) {
        url = metaStorage.getDomain(url, true)
      }
      service.overview_cache(url, ApiServiceV2_Scope.Subdomain, 'en-US').then((res) => {
        setError('')
        setDomainOverview(res)
        appStorage.setCoreTab('domainOverview', JSON.stringify(res), currentTab.id)
      }, (err) => {
        setError(err)
      })
    } catch (err) {
      setDomainOverview('')
      appStorage.setCoreTab('domainOverview', JSON.stringify(''), currentTab.id)
      setError(metaStorage.queryGeneralError)
    }
  }

  /**
   * Main template
   */
  const disabled = !data?.is_pro
  return (
    <div className={styles.DomainOverview} data-testid="DomainOverview">
      <h1>Domain Overview <MBPremium/> <MBMozAI/></h1>
      <MBAlert href={"https://moz.com/products/pro/pricing?utm_source=mozbar_v4&utm_medium=mozbar&utm_campaign=premium_new_signup&utm_content=domain-overview"}
               message={(<><strong>Get Mozbar Premium</strong> Available with Moz Pro</>)} button={"Sign Up"}
               href_token={"https://moz.com/products/pro/pricing?utm_source=mozbar_v4&utm_medium=mozbar&utm_campaign=premium_new_signup&utm_content=domain-overview"}
               message_token={(<><strong>Get Mozbar Premium</strong> Available with Moz Pro</>)} button_token={"Upgrade"}/>
      <MBQuota/>
      <p>Quickly discover key SEO metrics so you can better assess a site's online authority, performance, and health.</p>
      {error && (<MBErrorMessage message={error}/>)}
      <Grid container spacing={2}>
        <Grid xs={4} justifyContent="center" alignItems="center">
          <div className={'inputContainer'}>
            <div className={["input-label", domainErr].join(' ')}>Explore by</div>
            <FormControl size={"small"} fullWidth>
              <Select
                value={domain}
                displayEmpty={false}
                inputProps={{ 'aria-label': 'Without label' }}
                onChange={(ev: any) => setDomain(ev.target.value)}
              >
                {domainsData}
              </Select>
            </FormControl>
          </div>
        </Grid>
        <Grid xs={3} justifyContent="center" alignItems="center">
          <div className={"button-section-grid"}>
            <Button variant="contained" onClick={optimize} size="small" fullWidth disabled={disabled}>Analyze</Button>
          </div>
        </Grid>
        <Grid xs={5}></Grid>
      </Grid>
      {domainOverview && data?.is_pro && (<div className="mozbar-data-main">
          <div className={styles.overviewMain}>
            <Row>
              <Col xs={6}>
                <MBCard cardClass={styles.card}
                        cardTitle={metaStorage.domainAuthorityName}
                        cardTooltip={metaStorage.domainAuthorityTooltip}
                        cardValue={domainOverview.domain?.domain_authority}
                        showPie={true}
                        isBlur={false}
                        url={metaStorage.buildMetricsLink(currentTab.url, 'domain')}
                />
              </Col>
              <Col xs={6}>
                <MBCard cardClass={styles.card}
                        cardTitle={"Brand Authority™"}
                        cardTooltip={metaStorage.brandAuthorityTooltip}
                        cardValue={domainOverview.domain_extended?.brand_authority}
                        showPie={true}
                        isBlur={false}
                        url={metaStorage.buildMetricsLink(currentTab.url, 'domain')}
                />
              </Col>
              <Col xs={6}>
                <MBCard cardClass={styles.card}
                        cardTitle={"Page Authority"}
                        cardTooltip={metaStorage.pageAuhorityTooltip}
                        cardValue={domainOverview.page?.page_authority}
                        showPie={true}
                        isBlur={false}
                        url={metaStorage.buildMetricsLink(currentTab.url, 'page')}
                />
              </Col>
              <Col xs={6}>
                <MBCard cardClass={styles.card}
                        cardTitle={"Linking domains"}
                        cardTooltip={metaStorage.linkingDomainsTooltip}
                        cardValue={domainOverview.domain_extended?.linking_domains_count}
                        showPie={false}
                        isBlur={false}
                        url={metaStorage.buildMetricsLink(currentTab.url, 'domain')}
                />
              </Col>
              <Col xs={12}>
                <MBCard cardClass={styles.card}
                        cardTitle={"Ranking keywords"}
                        cardTooltip={""}
                        cardValue={domainOverview.domain_extended?.ranking_keywords_count + domainOverview.page_extended?.ranking_keywords_count}
                        showPie={false}
                        isBlur={false}
                        url={metaStorage.buildMetricsLink(currentTab.url, 'page')}
                />
              </Col>
            </Row>
          </div>
        </div>
      )}
    </div>
  );
}

export default DomainOverview;
