import React, { FC, useContext, useState } from 'react'
import styles from './Summary.module.scss';
import { getCurrentTab } from '../../api/browser'
import { AppStorage } from '../../helpers/AppStorage'
import { Col, Row } from 'react-bootstrap'
import { ExpandLess, ExpandMore } from '@mui/icons-material'
import MBCard from '../Common/MBCard/MBCard'
import MBGrader from '../Common/MBGrader/MBGrader'
import { ApiHelper } from '../../api/helper'
import { AppContext } from '../../config/state'
import MBPremium from '../Common/MBPremium/MBPremium'
import { MetaStorage } from '../../helpers/MetaStorage'
import { useNavigate } from 'react-router-dom'

interface SummaryProps {}

const resourceTabs = getCurrentTab()

const Summary: FC<SummaryProps> = () => {
  const metaStorage = new MetaStorage()
  const appStorage = new AppStorage()
  const currentTab = resourceTabs.read()[0]
  const {data, updateState} = useContext(AppContext)
  const navigate = useNavigate()

  const [keywordsGrid, updateKeywordsGrid] = useState<any>(
    appStorage.getCoreTabJson('summaryGrid', currentTab.id)
  )

  // Refresh page in case of action specified
  if (data?.action=='grader') {
    data.action = ''
    updateState({data: data})
    updateKeywordsGrid(appStorage.getCoreTabJson('summaryGrid', currentTab.id))
  }

  /**
   * Build keywords report
   */
  const keywords = []
  if (keywordsGrid) {
    // get factors for the page
    const data = (new ApiHelper()).factorsTotal(keywordsGrid.marks)
    const hurtingNumber: number = data.hurting
    const helpingNumber: number = data.helping

    const factors = (
      <Row>
        <Col xs={6}>
          <div className={[styles.hurtingheader, 'main-cursor'].join(' ')} onClick={(ev) => navigate('/hurting')}>{hurtingNumber}</div>
          <div><ExpandMore className={styles.hurting}/> Hurting</div>
        </Col>
        <Col xs={6}>
          <div className={[styles.helpingheader, 'main-cursor'].join(' ')} onClick={(ev) => navigate('/helping')}>{helpingNumber}</div>
          <div><ExpandLess className={styles.helping} /> Helping</div>
        </Col>
      </Row>
    )

    keywords.push(
      <Row>
        <Col xs={6}>
          <MBCard cardClass={styles.card}
                  cardTitle={"Page Score"}
                  cardTooltip={"We score pages on your site (0-100) based on how well-optimized those pages are for the keywords you track. Better scores might indicate good on-page use of the target keyword."}
                  cardValue={keywordsGrid.grade}
                  showPie={true}
                  isBlur={false}
                  url={'https://analytics.moz.com/pro/research/page-grader?keyword='
                    + appStorage.getCoreTab('summaryKeyword', currentTab.id) + "&url=" + currentTab.url}
          />
        </Col>
        <Col xs={6}>
          <MBCard cardClass={styles.card}
                  cardTitle={"Page Factors"}
                  cardTooltip={""}
                  customContent={factors}
                  cardValue={0}
                  showPie={true}
                  isBlur={false}
          />
        </Col>
      </Row>
    )
  }

  if (!keywords.length) keywords.push(<></>)

  /**
   * Main template
   */
  return (
    <div className={styles.Summary} data-testid="Summary">
      <h1>On-Page Grader <MBPremium/></h1>
      <MBGrader content={keywords}/>
    </div>
  )
}

export default Summary;
