import React, { FC, useContext, useState } from 'react'
import styles from './Content.module.scss';
import MBGrader from '../Common/MBGrader/MBGrader'
import { AppStorage } from '../../helpers/AppStorage'
import { getCurrentTab } from '../../api/browser'
import { AppContext } from '../../config/state'
import MBPremium from '../Common/MBPremium/MBPremium'

interface ContentProps {}

const resourceTabs = getCurrentTab()

const Content: FC<ContentProps> = () => {
  const appStorage = new AppStorage()
  const {data, updateState} = useContext(AppContext)
  const [currentTab] = resourceTabs.read()

  const [keywordsGrid, updateKeywordsGrid] = useState<any>(
    appStorage.getCoreTabJson('summaryGrid', currentTab.id)
  )

  // Refresh page in case of action specified
  if (data?.action === 'grader') {
    data.action = ''
    updateState({data: data})
    updateKeywordsGrid(appStorage.getCoreTabJson('summaryGrid', currentTab.id))
  }

  const keywords = []
  if (keywordsGrid) {

  }
  if (!keywords.length) keywords.push(<></>)

  return (
    <div className={styles.Content} data-testid="Content">
      <h1>On-Page Content Suggestions <MBPremium/></h1>
      <MBGrader content={keywords} description={"On Page-grader evaluates the current page for a keyword. Enter a keyword to see your page score. We will show you how to optimize the page and prioritize issues.” to “Here are topics influencing the SERP for the keyword you queried. Consider incorporating these topics into your content to help your topical authority"}/>
    </div>
  );
}

export default Content;
