import React, { FC, useContext, useState } from 'react'
import styles from './Settings.module.scss';
import { getCurrentTab } from '../../api/browser'
import { AppStorage } from '../../helpers/AppStorage'
import { AppContext } from '../../config/state'
import { Add, Delete, Edit } from '@mui/icons-material'
import { Chip, FormControl, MenuItem, Select, Switch, TextField } from '@mui/material'
import { useNavigate } from 'react-router-dom'
import { AppStorageProfile, ProfileInterface } from '../../helpers/AppStorageProfile'
import { Col, Row } from 'react-bootstrap'
import { EventStorage } from '../../helpers/EventStorage'
import { LocalStorage } from '../../helpers/LocalStorage'
import { MetaStorage } from '../../helpers/MetaStorage'
import { ApiServiceV2, ApiServiceV2_Scope } from '../../api/api_v2'

interface SettingsProps {}

const resourceTabs = getCurrentTab()

const Settings: FC<SettingsProps> = () => {
  const navigate = useNavigate();

  const app = new AppStorage()
  const eventStorage = new EventStorage()
  const ls = new LocalStorage()

  const {data, updateState} = useContext(AppContext)

  const [showToolbar, setToolbar] = useState(data?.toolbar)
  const [showSERP, setSERP] = useState(data?.serp)
  const [showPlaces, setPlaces] = useState(data?.places)
  const [showTheme, setTheme] = useState(data?.is_dark)
  const [showDaMode, setDaMode] = useState(data?.da_mode)
  const [changeProfiles, updateChangeProfiles] = useState(false)
  const [blockList, updateBlockList] = useState(data?.block)
  const [currentTab] = resourceTabs.read()

  /**
   * Manage toolbar visibility
   * @param event
   * @param func
   * @param name
   */
  const changeToolbar = (event: any, func: React.Dispatch<React.SetStateAction<any>>, name:string) => {
    func(event.target.checked)
    if (event.target.checked) {
      if (name==app.SETTING_DAMODE) {
        const meta = new MetaStorage()
        const api2 = new ApiServiceV2(data?.token)
        const url = meta.getUrlNoQuery(currentTab.url)
        api2.overview_cache(url, ApiServiceV2_Scope.Url).then((metrics: any) => {
          eventStorage.sendTabMessage(currentTab.id,
            { type: eventStorage.SOURCE_CONTENT, from: eventStorage.SOURCE_EXTENSION, message: "show." + name, data: metrics?.domain?.domain_authority })
        })
      } else {
        eventStorage.sendTabMessage(currentTab.id,
          { type: eventStorage.SOURCE_CONTENT, from: eventStorage.SOURCE_EXTENSION, message: "show." + name })
      }
    } else {
      eventStorage.sendTabMessage(currentTab.id,
        { type: eventStorage.SOURCE_CONTENT, from: eventStorage.SOURCE_EXTENSION, message: "hide." + name })
    }
    updateState(app.prepareState(data, name, event.target.checked))
    ls.push('config', {[name]: event.target.checked})
  }

  /**
   * Manage dark mode for extension and toolbar
   * @param event
   * @param func
   * @param name
   */
  const changeSelect = (event: any, func: React.Dispatch<React.SetStateAction<any>>, name:string) => {
    const isDarkMode = event.target.value == 'dark' ? true : false
    func(isDarkMode)
    updateState(app.prepareState(data, 'is_dark', isDarkMode))
    ls.push('config', {'theme': isDarkMode})
  }

  const reviewProfiles = (profiles: any) => {
    updateChangeProfiles(!changeProfiles)
    ls.push('config', {'profiles': profiles})
  }

  /**
   * Build profile icon and name
   */
  const renderIcon = (icon: ProfileInterface) => {
      return (
        <>
          <span className="mozbar-icon-place">
            <img className="mozbar-icon" src={meta.getSEImage(icon.engine ?? '')}/>
          </span>
          <span style={{marginLeft: "10px"}}>{icon.name.length>20 ? icon.name.substring(0,18) + '...' : icon.name}</span>
        </>
      )
  }

  const meta = new MetaStorage()
  const profilesContent = []
  const profileStorage = new AppStorageProfile()
  const profiles = profileStorage.profiles()
  for(let f=0; f<profiles.length; f++) {
    const item = profiles[f]
    profilesContent.push(
      <Row className="mozbar-grid-line">
        <Col xs={5} className="mozbar-grid-icon-align">
          {renderIcon(item)}
        </Col>
        <Col xs={4} className="mozbar-grid-icon-align">
          {meta.get_country_name(item.country)?.country}
        </Col>
        <Col xs={3}>
          <p className="edit-button-label">
            <span onClick={(ev) => navigate('/addprofile/' + f)}>
              <Edit fontSize={'small'}/>&nbsp;&nbsp;Edit
            </span>
            <span onClick={(ev) => {
              reviewProfiles(profileStorage.deleteProfile(f))
            }}>
              <Delete fontSize={'small'}/>
            </span>
          </p>
        </Col>
      </Row>
    )
  }

  /**
   * Generate main template
   */
  return (
    <div className={styles.Settings} data-testid="Settings">
      <h1>Settings</h1>
      <p className={'para-header'}>Choose between light mode and dark mode for both the MozBar and Moz Extension</p>
      <div className={'inputContainer'}>
        <div className={'input-label'}>Mode</div>
        <FormControl size={'small'}>
          <Select
            value={showTheme ? 'dark' : 'light'}
            displayEmpty={false}
            inputProps={{ 'aria-label': 'Without label' }}
            onChange={(ev: any) => changeSelect(ev, setTheme, app.SETTING_THEME)}
          >
            <MenuItem value={'light'}>Light Mode</MenuItem>
            <MenuItem value={'dark'}>Dark Mode</MenuItem>
          </Select>
        </FormControl>
      </div>
      <br/>
      <p className={'para-header'}>Features</p>
      <div className={'inputContainer'}>
        <Switch
          type={'checkbox'}
          checked={showToolbar}
          onChange={(ev) => changeToolbar(ev, setToolbar, app.SETTING_TOOLBAR)}
          className={'checkbox'}
        /> Enable MozBar
      </div>
      {data?.token && (
        <div className={'inputContainer'}>
          <Switch
            type={'checkbox'}
            checked={showDaMode}
            onChange={(ev) => changeToolbar(ev, setDaMode, app.SETTING_DAMODE)}
            className={'checkbox'}
          /> Enable DA mode
        </div>)}
      <div className={'inputContainer'}>
        <Switch
          type={'checkbox'}
          checked={showSERP}
          onChange={(ev) => changeToolbar(ev, setSERP, app.SETTING_SERP)}
          className={'checkbox'}
        /> Enable SERP Overlay and Search Features
      </div>
      <div className={'inputContainer'}>
        <Switch
          type={'checkbox'}
          checked={showPlaces}
          onChange={(ev) => changeToolbar(ev, setPlaces, app.SETTING_PLACES)}
          className={'checkbox'}
        /> Enable SERP Overlay on Places <Chip sx={{backgroundColor: "#54E8CC", color: "#000", borderRadius: "15px", fontSize: "13px", fontWeight: 400}} size={"small"} label={"Beta"}/>
      </div>

      <br/>
      <p className={'para-header'}>Search Profiles</p>
      <div className="mozbar-grid">
        {profilesContent}
      </div>
      <p className={'add-button-label'} onClick={(ev) => navigate('/addprofile')}>
        <Add fontSize={'small'} sx={{ float: 'left' }}/>&nbsp;&nbsp;&nbsp;Add profile</p>

      <br/>
      <p className={'para-header'}>Block list</p>
      <div className="mozbar-grid">
        <p>Add domains to the box below to hide MozBar.</p>
        <div className={'inputContainer'}>
          <FormControl fullWidth>
            <TextField
              minRows={5}
              multiline={true}
              size={'small'}
              value={blockList}
              inputProps={{ 'aria-label': 'Without label' }}
              onChange={(ev: any) => {
                updateBlockList(ev.target.value)
                ls.push('config', { 'block': ev.target.value })
              }}
            />
          </FormControl>
        </div>
      </div>
      <br/>
    </div>
  );
}

export default Settings;
