import { ApiServiceV2, ApiServiceV2_Scope } from '../api/api_v2'
import { LocalStorage } from './LocalStorage'
import { MetaStorage } from './MetaStorage'

class EventStorage {
  public SOURCE_CONTENT = 'content'
  public SOURCE_BACKGROUND = 'background'
  public SOURCE_EXTENSION = 'extension'

  public tabs() {
    if (chrome && chrome.tabs)
      return chrome.tabs
    else
      return undefined
  }

  public action() {
    if (chrome && chrome.action)
      return chrome.action
    else
      return undefined
  }

  public cookies() {
    if (chrome && chrome.cookies)
      return chrome.cookies
    else
      return undefined
  }

  /**
   * Send message
   * @param message
   */
  public sendMessage(message: any) {
    return chrome.runtime.sendMessage(message)
  }

  /**
   * Send event to content script
   * @param tabId
   */
  public sendTabMessage(tabId: number | undefined, message: any) {
    if (tabId) {
      const tabsApi = this.tabs()
      if (tabsApi !== undefined) {
        tabsApi.query({active: true, currentWindow: true},function(tabs) {
          tabsApi.sendMessage(tabId, { ...message, tabId: tabId }, (response) => {
          })
        })
      }
    }
  }

  /**
   * Build messahe in single format
   * @param to
   * @param from
   * @param message
   */
  public buildMessage(to: string, from: string, message: any, data: any) {
    // Do parse and stringify to make sure no methods exists in object
    return { type: to, from: from, message: message, data: JSON.parse(JSON.stringify(data)) }
  }

  /**
   * Send message to open link
   * @param url
   */
  public openLink(url: string | undefined) {
    if (url) {
      this.sendMessage(
        this.buildMessage(
          this.SOURCE_BACKGROUND, this.SOURCE_EXTENSION, 'openlink', url
        )
      )
    }
  }

  public sendTabToolbarRefresh(tabId: number, source: string, config?: any) {
    this.sendTabMessage(tabId, this.buildMessage(
      this.SOURCE_CONTENT, source, 'refresh', config
    ))
  }

  /**
   * Handler for all extension events
   *
   * @param response
   */
  public sendTabStatusData(tabId: number, source: string, url: string | undefined, token?: string | undefined) {
    // Do page query
    const api = new ApiServiceV2()
    const ls = new LocalStorage()
    const meta = new MetaStorage()

    url = meta.getUrlNoQuery(url)
    const key = 'toolbar_url_' + token + '_' + btoa(url ? url : '')
    ls.storage().local.get(key, (result: any) => {
      const cacheLife = meta.cacheLifetime
      const current = new Date().getTime() / 1000
      if (result[key] && result[key].created + cacheLife >= current) {
        this.sendTabMessage(tabId, this.buildMessage(
          this.SOURCE_CONTENT, source, 'status', result[key]
        ))
      } else {
        if (url) {
          api.setToken(token)
          api.overview_cache(url, ApiServiceV2_Scope.Url).then((data: any) => {
            const info = {
              page_authority: data?.page?.page_authority,
              domain_authority: data?.domain?.domain_authority,
              brand_authority: data?.domain_extended?.brand_authority,
              da: {
                ld: data?.domain_extended?.linking_domains_count,
                tl: data?.domain_extended?.linking_pages_count,
                rk: data?.domain_extended?.ranking_keywords_count
              },
              pa: {
                ld: data?.page_extended?.linking_domains_count,
                tl: data?.page?.linking_pages_count,
                rk: data?.page_extended?.ranking_keywords_count,
                sc: data?.page_extended?.spam_score
              },
              links: [],
              created: current
            }
            ls.set(key, info)
            this.sendTabMessage(tabId, this.buildMessage(
              this.SOURCE_CONTENT, source, 'status', info
            ))
          }, (err) => {
            this.sendTabMessage(tabId, this.buildMessage(
              this.SOURCE_CONTENT, source, 'status', {}
            ))
          })
        }
      }
    })
  }
}

export {EventStorage}
