import React, { FC, useState } from 'react'
import styles from './AddProfile.module.scss';
import {
  Button,
  Divider,
  FormControl,
  Link, ListItemIcon, ListItemText,
  MenuItem,
  Select, Stack,
  TextField
} from '@mui/material'
import { useNavigate, useParams } from 'react-router-dom'
import { AppStorageProfile, ProfileInterface } from '../../helpers/AppStorageProfile'
import { MetaStorage } from '../../helpers/MetaStorage'
import { FlagIcon, FlagIconCode } from 'react-flag-kit'
import { LocalStorage } from '../../helpers/LocalStorage'

interface AddProfileProps {}

const AddProfile: FC<AddProfileProps> = () => {
  const profileStorage = new AppStorageProfile()

  const navigate = useNavigate();
  const { id } = useParams();

  /**
   * Change select data
   * @param event
   * @param func
   */
  const changeSE = (engine: string | undefined) => {
    let countries:any[] = []
    switch(engine) {
      case 'google':
        countries = new MetaStorage().google_countries()
        break;
      case 'yahoo':
        countries = new MetaStorage().yahoo_countries()
        break;
      case 'bing':
        countries = new MetaStorage().bing_countries()
        break;
    }
    let contriesData = []
    if (Array.isArray(countries) && countries.length>0) {
      countries.forEach((item) => {
        contriesData.push(
          <MenuItem value={item.code}>
            <Stack direction={"row"} spacing={0} justifyContent={'flex-start'} justifyItems={"center"} alignItems={"center"} sx={{height: "20px !important"}}>
              <ListItemIcon sx={{minWidth: "30px"}}>
                <FlagIcon code={item.code as FlagIconCode} width={"22px"} height={"16px"}/>
              </ListItemIcon>
              <ListItemText primary={item.country} sx={{marginTop: "8px"}} />
            </Stack>
          </MenuItem>
        )
      })
    } else {
      contriesData.push(<></>)
    }
    return contriesData
  }

  /**
   * Change select data
   * @param event
   * @param func
   */
  const changeCountry = (country: string | undefined) => {
    let regionsData = []
    let regions = new MetaStorage().regions(country)
    if (regions) {
      for (const [key, value] of Object.entries(regions)) {
        regionsData.push(
          <MenuItem value={key}>{value}</MenuItem>
        )
      }
    } else {
      regionsData.push(<></>)
    }
    return regionsData
  }

  /**
   * Init profile
   *
   */
  let defaultEngine : string | undefined = ''
  let defaultCountry : string | undefined  = ''
  let defaultRegion : string | undefined = ''
  let defaultCity : string | undefined  = ''
  let defaultProfile : string | undefined  = ''
  let defaultCountries = [<></>]
  let defaultRegions = [<></>]
  let profileIndex = -1
  if (Number(id) >= 0) {
    profileIndex = Number(id)
    const profile = profileStorage.getProfile(profileIndex)
    if (profile) {
      defaultEngine = profile.engine
      defaultCountry = profile.country
      defaultRegion = profile.region
      defaultProfile = profile.name
      defaultCountries = changeSE(defaultEngine)
      defaultRegions = changeCountry(defaultCountry)
    }
  }

  const [countriesData, updateCountriesData] = useState<any>(defaultCountries)
  const [regionsData, updateRegionsData] = useState<any>(defaultRegions)

  const [searchEngine, setSearchEngine] = useState(defaultEngine)
  const [searchEngineErr, setSearchEngineErr] = useState('')

  const [country, setCountry] = useState(defaultCountry)
  const [countryErr, setCountryErr] = useState('')

  const [region, setRegion] = useState(defaultRegion)

  const [profile, setProfile] = useState(defaultProfile)
  const [profileErr, setProfileErr] = useState('')


  /**
   * Save profile data
   */
  const saveProfile = () => {
    let isError = false

    setSearchEngineErr('')
    setCountryErr('')
    setProfileErr('')

    if (!profile && profile.length==0) {
      setProfileErr('error-highlight')
      isError = true
    }
    if (!searchEngine) {
      setSearchEngineErr('error-highlight')
      isError = true
    }
    if (!country) {
      setCountryErr('error-highlight')
      isError = true
    }

    if (isError) return

    // Save profile data
    const item: ProfileInterface = {
      engine: searchEngine,
      country: country,
      region: region,
      name: profile
    }
    if (profileIndex >= 0) {
      // Update profile
      profileStorage.editProfile(profileIndex, item)
    } else {
      // Create new profile
      profileStorage.addProfile(item)
    }

    const ls = new LocalStorage()
    ls.push('config', {'profiles': profileStorage.profiles()})

    navigate('/settings')
  }

  const se = (type: string, country: string, image: string) => {
    return (
      <MenuItem value={type}>
        <Stack direction={"row"} spacing={0} justifyContent={'flex-start'} justifyItems={"flex-start"} alignItems={"center"} sx={{height: "20px !important"}}>
          <ListItemIcon style={{textAlign: "center", display: "block", minWidth: "22px"}}>
            <img src={image} height={"16px"}/>
          </ListItemIcon>
          <ListItemText primary={country} sx={{marginTop: "8px", marginLeft: "10px", textAlign: "left"}} />
        </Stack>
      </MenuItem>
    )
  }

  /**
   * Generate main template
   */
  const meta = new MetaStorage()
  return (
    <div className={styles.AddProfile} data-testid="AddProfile">
      <h1>Search Profile</h1>
      <p>Create a custom search profile so you can rerun targeted search results</p>

      <Divider component="div" role="presentation"/>

      <div className={'form-controls'}>
        <div className={'inputContainer'}>
          <div className={["input-label", searchEngineErr].join(' ')}>Search engine (required)</div>
          <FormControl sx={{ m: 1, minWidth: 180 }} size={"small"} fullWidth>
            <Select
              value={searchEngine}
              displayEmpty={false}
              inputProps={{ 'aria-label': 'Without label' }}
              onChange={(ev: any) => {
                setSearchEngine(ev.target.value)
                updateCountriesData(changeSE(ev.target.value))
              }}
            >
              {se('google', 'Google', meta.getSEImage('google'))}
              {se('bing', 'Bing', meta.getSEImage('bing'))}
              {se('yahoo', 'Yahoo', meta.getSEImage('yahoo'))}
            </Select>
          </FormControl>
        </div>

        <div className={'inputContainer'}>
          <div className={["input-label", countryErr].join(' ')}>Country (required)</div>
          <FormControl sx={{ m: 1, minWidth: 180 }} size={"small"} fullWidth>
            <Select
              value={country}
              displayEmpty={false}
              inputProps={{ 'aria-label': 'Without label' }}
              onChange={(ev: any) => {
                setCountry(ev.target.value)
                updateRegionsData(changeCountry(ev.target.value))
              }}
            >
              {countriesData}
            </Select>
          </FormControl>
        </div>

        <div className={'inputContainer'}>
          <div className={["input-label"].join(' ')}>Region (optional)</div>
          <FormControl sx={{ m: 1, minWidth: 180 }} size={"small"} fullWidth>
            <Select
              value={region}
              displayEmpty={false}
              inputProps={{ 'aria-label': 'Without label' }}
              onChange={(ev: any) => setRegion(ev.target.value)}
            >
              {regionsData}
            </Select>
          </FormControl>
        </div>

        <div className={'inputContainer'}>
          <div className={["input-label", profileErr].join(' ')}>Search profile name (required)</div>
          <FormControl sx={{ m: 1, minWidth: 180 }} fullWidth>
            <TextField
              size={"small"}
              value={profile}
              inputProps={{ 'aria-label': 'Without label' }}
              onChange={(ev: any) => {setProfile(ev.target.value)}}
            />
          </FormControl>
        </div>

        <Divider component="div" role="presentation" sx={{pb: 2}}/>

        <div className="button-section" >
          <Link onClick={(ev) => navigate('/settings')}>Cancel</Link>
          <Button variant="contained" onClick={saveProfile} size="large">Save profile</Button>
        </div>
      </div>
    </div>
  );
}

export default AddProfile;
