import { UserState } from '../config/state'
import { ApiServiceV2 } from '../api/api_v2'
import { AppStorageProfile } from './AppStorageProfile'
import { LocalStorage } from './LocalStorage'

class AppStorage {
  public SETTING_SERP = 'serp'
  public SETTING_PLACES = 'places'
  public SETTING_THEME = 'theme'
  public SETTING_TOOLBAR = 'toolbar'
  public SETTING_DAMODE = 'da_mode'
  public SETTING_TOKEN = 'token'
  public PRO_PLAN = 'plan'

  /**
   * Refresh local state
   */
  public userLookup(data: UserState | undefined, updateState: any, token?: string, currentTab?: any) {
    const ls = new LocalStorage()

    return new Promise((resolve, reject) => {
      if (!token) {
        // clean up local session data
        updateState({
          data: {
            user: '', email: '', token: '', session: '', is_pro: false, avatar: '', is_dark: false,
            quota_max: 0, quota_current: 0, quota_k_max: 0, quota_k_current: 0
          }
        })
        // Cleanup user data
        ls.push('config',
          {
            token: '', is_pro: false, user: '', avatar: '',
            quota_max: 0, quota_current: 0, quota_k_max: 0, quota_k_current: 0
          },
          currentTab.id, data?.toolbar, data?.serp, currentTab.url
        )
        return;
      }

      // do user lookup based on a token if user is not defined
      if (!data?.user) {
        const api = new ApiServiceV2()
        api.setToken(token)
        api.status().then(
          (res) => {
            const token = res.data?.result?.session?.id
            if (token) {
              const name = res.data?.result?.session?.data?.display_name ?
                res.data?.result?.session?.data?.display_name : ''
              const email = res.data?.result?.session?.data?.email ?
                res.data?.result?.session?.data?.email : ''
              const avatar = res.data?.result?.session?.data?.avatar ?
                res.data?.result?.session?.data?.avatar : ''
              const session = res.data
              const state = {
                data: {
                  ...data,
                  toolbar: true, // enable toolbar on user sign in
                  da_mode: true, // enable da mode on user sign in
                  serp: true, // enable serp on user sign in
                  places: false, // disable places by default
                  token: token,
                  email: email,
                  user: name,
                  avatar: avatar,
                  session: session,
                  is_pro: session?.result?.session?.data?.account_services?.search?.limits?.mozbar?.detail == 2 ? true : false
                },
                quota_max: 0,
                quota_current: 0,
                quota_k_max: 0,
                quota_k_current: 0
              }
              updateState(state)
              // Store user data
              ls.push('config', state.data, currentTab.id, true, true, currentTab.url)
              resolve(true)
            } else {
              const state = {
                data: {
                  ...data,
                  user: '',
                  email: '',
                  session: '',
                  avatar: '',
                  token: '',
                  is_pro: false,
                  quota_max: undefined,
                  quota_current: undefined,
                  quota_k_max: undefined,
                  quota_k_current: undefined
                }
              }
              updateState(state)
              // Cleanup user data
              ls.push('config', state.data, currentTab.id, false, false, currentTab.url)
              resolve(false)
            }
          },
          (err) => {
            // Cleanup user data
            ls.push('config',
              {
                token: '',
                is_pro: false,
                user: '',
                quota_max: undefined,
                quota_current: undefined,
                quota_k_max: undefined,
                quota_k_current: undefined
              }, currentTab.id, data?.toolbar, data?.serp, currentTab.url
            )
            reject()
          })
      }
    })
  }

  /**
   * Set value to local storage
   * @param name
   * @param value
   */
  public set(name: string, value: string) {
    localStorage.setItem(name, value);
  }

  /**
   * Get value from local storage
   * @param name
   */
  public get(name: string) {
    return localStorage.getItem(name);
  }

  /**
   * Get setting by name
   * @param name
   */
  public getCore(name: string) {
    const state = this.get(name)
    let settingsState
    if (state) {
      settingsState = state
    } else {
      settingsState = ''
    }
    return settingsState
  }

  /**
   * Get setting by name
   * @param name
   */
  public getCoreTab(name: string, tabId: number) {
    const state = this.get(name + '_' + tabId)
    let settingsState
    if (state) {
      settingsState = state
    } else {
      settingsState = ''
    }
    return settingsState
  }

  /**
   * Get setting by name
   * @param name
   */
  public getCoreTabJson(name: string, tabId?: number) {
    const state = this.get(tabId ? name + '_' + tabId : name)
    let settingsState
    if (state) {
      try {
        settingsState = JSON.parse(state)
      }
      catch (e) {
        settingsState = ''
      }
    } else {
      settingsState = ''
    }
    return settingsState
  }


  /**
   * Set settings value
   * @param name
   * @param value
   */
  public setCore(name: string, value: string) {
    this.set(name, value)
  }

  /**
   * Set settings value
   * @param name
   * @param value
   */
  public setCoreTab(name: string, value: string, tabId?: number) {
    if (tabId)
      this.set(name + '_' + tabId, value)
    else
      this.set(name, value)
  }

  /**
   * Build config
   * @param context
   */
  public config(context: UserState | undefined) {
    const profilesStorage = new AppStorageProfile()
    const config = {
      toolbar: context?.toolbar,
      serp: context?.serp,
      places: context?.places,
      followed: this.getCore('followed'),
      nofollow: this.getCore('nofollow'),
      external: this.getCore('external'),
      internal: this.getCore('internal'),
      keyword: this.getCore('keyword'),
      keywordhighlight: this.getCore('keywordhighlight'),
      token: context?.token,
      profiles: profilesStorage.profiles(),
      theme: context?.is_dark,
      is_pro: context?.is_pro,
      dock: context?.dock,
      block: context?.block,
      quota_max: context?.quota_max,
      quota_current: context?.quota_current,
      quota_k_max: context?.quota_k_max,
      quota_k_current: context?.quota_k_current,
    }
    return config
  }

  /**
   * Prepare new state based on new value
   * @param context
   * @param name
   * @param value
   */
  public prepareState(context: UserState | undefined, name: string, value: any) {
    const data: UserState = {...context, [name]: value}
    return { data: data }
  }

  /**
   * Update user's quota
   * @param Quota
   */
  public setQuota(quota: any, quota_type: string = 'data') {
    let data
    const ls = new LocalStorage()
    if (quota_type=='data') {
      // Regular quota
      data = {
        'quota_max': quota?.allotted,
        'quota_current': quota?.used,
      }
    } else {
      // Keyword quota
      data = {
        'quota_k_max': quota?.allotted,
        'quota_k_current': quota?.used,
      }
    }
    ls.push('config', {
      ...data,
      'period_start': quota?.period_start,
      'period_reset': quota?.period_reset,
    })
  }
}

export {AppStorage}
