import React, { FC, useEffect, useState } from 'react'
import styles from './Markup.module.scss';
import { EventStorage } from '../../helpers/EventStorage'
import { getCurrentTab } from '../../api/browser'
import { AppStorage } from '../../helpers/AppStorage'
import MBBox from '../Common/MBBox/MBBox'

interface MarkupProps {}

const resourceTabs = getCurrentTab()

const Markup: FC<MarkupProps> = () => {
  const appStorage = new AppStorage()
  const eventStorage = new EventStorage()
  const tabs = resourceTabs.read()
  const currentTab = tabs[0]

  const [expandAll, updateExpandAll] = useState(false)
  const [expandFirst, updateExpandFirst] = useState(true)
  const [markupSchema, updateMarkupSchema] = useState(
    appStorage.getCoreTabJson('markupSchema', currentTab.id)
  )

  useEffect(() => {
    eventStorage.sendTabMessage(currentTab.id,
      eventStorage.buildMessage(eventStorage.SOURCE_CONTENT, eventStorage.SOURCE_EXTENSION, "schema", {})
    )
    chrome.runtime.onMessage.addListener(response => {
      if (response.type === eventStorage.SOURCE_EXTENSION) {
        switch (response.message) {
          case 'schema':
            updateMarkupSchema(response.data)
            appStorage.setCoreTab('markupSchema', JSON.stringify(response.data), currentTab.id)
            break
        }
      }
    })
  }, [])

  /**
   * Parse JSON and show details
   */
  const showObject = (object: any, title: string, copy?: boolean, expanded?: boolean, copyText?: string, showExpand?: boolean, showExpandFunc?: any) => {
    let name = ''
    if (object instanceof Object) {
      object.forEach((itm: any) => {
        if (itm && itm.props && itm.props.children && itm.props.children.length > 0) {
          if (itm.props?.children[0]?.props?.children === '@context') {
            name = itm.props?.children[2]
          }
          if (itm.props?.children[0]?.props?.children === '@type') {
            name = itm.props?.children[2]
          }
        }
      })
    }

    const element = {
      name: name ? name : title,
      secondary: '',
      content: object,
      copy: copy
    }
    return (
      <MBBox item={element} copy={copy} collapse_enabled={true} expanded={expanded} copyText={copyText} showExpand={showExpand} showExpandFunc={showExpandFunc}/>
    )
  }

  const showJson = (items: any, expandAll?: boolean): any => {
    const data = []
    for (const key in items) {
      if (Array.isArray(items[key])) {
        items[key].forEach((item: any) => {
          if (item instanceof Object) {
            data.push(
              showObject(
                showJson(item, expandAll),
                key,
                false,
                false || expandAll
              )
            )
          } else {
            data.push(
              <div><strong>{key}</strong>: {item}</div>
            )
          }
        })
      } else if (items[key] instanceof Object) {
        data.push(
          showObject(
            showJson(items[key], expandAll),
            key,
            false,
            false || expandAll
          )
        )
      } else {
        data.push(
          <div><strong>{key}</strong>: {items[key]}</div>
        )
      }
    }
    return data
  }

  /**
   * Function to handle expand all MBBoxes
   */
  const showExpandFunc = () => {
    const value = !expandAll
    updateExpandAll(value)
    updateExpandFirst(value)
  }

  /**
   * Build tree from JSON/structure JSON
   * @param markupSchema
   */
  const buildMarkup = (markupSchema: any, expandFirst: boolean, expandAll: boolean) => {
    const copyText = JSON.stringify(markupSchema)
    const object = showObject(
      showJson(markupSchema, expandAll),
      '',
      true,
      expandFirst,
      copyText,
      true,
      showExpandFunc
    )
    contents.push(<p>The following types of structured data (JSON-LD) have been detected.</p>)
    contents.push(
      object
    )
  }
  const contents = []
  if (markupSchema) {
    buildMarkup(markupSchema, expandFirst, expandAll)
  } else {
    contents.push(<p>No structured data (JSON-LD) was found on this page. Implementing schema.org structured data on a page lets search engines understand more about the content and can allow pages to be shown in different search features, such as Reviews and Recipes.</p>)
  }

  return (
    <div className={styles.Markup} data-testid="Markup">
      <h1>Structured Data (JSON-LD)</h1>
      <p>Implementing schema.org structured data in a page lets search engines understand more about the content—and can allow pages to be shown in different search features, such as Reviews and Recipes.</p>
      {contents}
    </div>
  );
}

export default Markup;
