import React, { FC, useContext, useState } from 'react'
import styles from './Login.module.scss';
import { AppContext, UserState } from '../../config/state'
import { ApiServiceV2, ApiServiceV2_Scope } from '../../api/api_v2'
import { AxiosError } from 'axios'
import { AppStorage } from '../../helpers/AppStorage'
import { Button, Divider, FormControl, Link, TextField } from '@mui/material'
import { ArrowForward } from '@mui/icons-material'
import { EventStorage } from '../../helpers/EventStorage'
import { MetaStorage } from '../../helpers/MetaStorage'
import MBError from '../Common/MBError/MBError'
import { LocalStorage } from '../../helpers/LocalStorage'
import { getCurrentTab } from '../../api/browser'
import { useNavigate } from 'react-router-dom'

interface LoginProps {}

const resourceTabs = getCurrentTab()

const Login: FC<LoginProps> = () => {
  const app = new AppStorage()
  const eventStorage = new EventStorage()
  const metaStorage = new MetaStorage()

  const {data, updateState} = useContext(AppContext)
  const navigate = useNavigate()
  const [email, setEmail] = useState('')
  const [password, setPassword] = useState('')
  const [emailErr, setEmailError] = useState('')
  const [passwordErr, setPasswordError] = useState('')
  const [loginErr, setLoginError] = useState(false)
  const [currentTab] = resourceTabs.read()

  /**
   * Sign user in event
   */
  const onSignIn = async () => {
    // Set initial error values to empty
    let isErr = false
    setEmailError('')
    setPasswordError('')

    // Check if the user has entered both fields correctly
    if ('' === email) {
      setEmailError('error-highlight')
      isErr = true
    }

    if (!/^[\w-\.]+@([\w-]+\.)+[\w-]{2,10}$/.test(email)) {
      setEmailError('error-highlight')
      isErr = true
    }

    if ('' === password) {
      setPasswordError('error-highlight')
      isErr = true
    }

    if (password.length < 5) {
      setPasswordError('error-highlight')
      isErr = true
    }

    if (isErr) return

    // Sing in user and remember token
    const ls = new LocalStorage()
    const service = new ApiServiceV2()
    const result = service.login(email, password)
    result.then( (res) => {
      const token = res.data?.result?.session?.id
      updateState(app.prepareState(data, 'token', token))
      app.userLookup(data, updateState, token, currentTab).then((res) => {
        // Show toolbar
        eventStorage.sendTabMessage(currentTab.id, eventStorage.buildMessage(
          eventStorage.SOURCE_CONTENT, eventStorage.SOURCE_EXTENSION, "show." + app.SETTING_TOOLBAR, {}
        ))
        // Show DA mode
        const api2 = new ApiServiceV2(data?.token)
        const url = metaStorage.getUrlNoQuery(currentTab.url)
        api2.overview_cache(url, ApiServiceV2_Scope.Url).then((metrics: any) => {
          eventStorage.sendTabMessage(currentTab.id, eventStorage.buildMessage(
            eventStorage.SOURCE_CONTENT, eventStorage.SOURCE_EXTENSION, "show." + app.SETTING_DAMODE, metrics?.domain?.domain_authority
          ))
        })
      })
      navigate('/settings')
    }, (err: AxiosError) => {
      updateState(app.prepareState(data, 'token', ''))
      ls.push('config', {token: '', is_pro: false, user: '', quota_max: undefined, quota_current:undefined, quota_k_max:undefined, quota_k_current: undefined}, currentTab.id, data?.toolbar, data?.serp, currentTab.url)
      setLoginError(true)
    })
  }

  /**
   * Sign user out event
   */
  const onSignOut = async () => {
    // Clear cache before new sign in
    const ls = new LocalStorage()
    ls.clear().then((error) => {
      app.userLookup(data, updateState, '' , currentTab)
    })
  }

  /**
   * Main template
   */
  if (!data?.token) {
    return (
      <div className={styles.Login} data-testid="Login">
        <h1 className={styles.header}>Log in</h1>
        <p className={styles.para}>Don't have an account? <a
          onClick={(ev) => eventStorage.openLink(metaStorage.signupUrl)}>Sign up</a></p>
        <Divider className={styles.divider} component="div" role="presentation"/>
        <div className={'inputContainer'}>
          <div className={['input-label', emailErr].join(' ')}>Email (required)</div>
          <FormControl sx={{ m: 1, minWidth: 180 }} fullWidth>
            <TextField
              sx={{ borderWidth: '2px' }}
              placeholder="Enter your email here"
              size={'medium'}
              value={email}
              inputProps={{ 'aria-label': 'Without label' }}
              onChange={(ev: any) => {setEmail(ev.target.value)}}
            />
          </FormControl>
        </div>

        <div className={'inputContainer'}>
          <div className={['input-label', passwordErr].join(' ')}>Password (required)</div>
          <FormControl sx={{ m: 1, minWidth: 180 }} fullWidth>
            <TextField
              type={'password'}
              sx={{ borderWidth: '2px' }}
              placeholder="Enter your password here"
              size={'medium'}
              value={password}
              inputProps={{ 'aria-label': 'Without label' }}
              onChange={(ev: any) => {setPassword(ev.target.value)}}
            />
          </FormControl>
        </div>

        <div className={'inputContainer'}>
          Or <a
          onClick={(ev) => eventStorage.openLink(metaStorage.signInUrl)}>log in via your Moz Pro Account</a>
        </div>

        {loginErr && (
          <MBError message={'Invalid email or password.'}/>
        )}

        <Divider className={styles.divider} component="div" role="presentation"/>
        <div className="button-section">
          <div className={styles.trouble}>Having troubles logging in?<br/><a
            onClick={(ev) => eventStorage.openLink(metaStorage.forgotPasswordUrl)}>Reset Password</a></div>
          <Button variant="contained" onClick={onSignIn} size="large">Log in <ArrowForward/></Button>
        </div>
      </div>
    )
  } else {
    return (
      <div className={styles.mainContainer} data-testid="Login">
        <h1>Log out</h1>
        <br/>
        <div className={'inputContainer'}>
        <div>Welcome back {data?.user}</div>
        </div>
        <br/>
        <div className="button-section" style={{textAlign: "left"}}>
          <Button variant="contained" onClick={onSignOut} size="large">Log out <ArrowForward/></Button>
        </div>
      </div>
    )
  }
};

export default Login;
