import React, { FC, useEffect, useState } from 'react'
import styles from './Status.module.scss';
import { getCurrentTab } from '../../api/browser'
import { TabStorage } from '../../helpers/TabStorage'
import MBCard from '../Common/MBCard/MBCard'

interface StatusProps {}

const resourceTabs = getCurrentTab()

const Status: FC<StatusProps> = () => {
  const tabs = resourceTabs.read()
  const currentTab = tabs[0]
  const tabStorage = new TabStorage()

  const [statusLine, setStatusLine] = useState('')
  const [content, setContent] = useState('')

  useEffect(() => {
    tabStorage.getStatusLine(currentTab.id, setStatusLine)
    tabStorage.getTabsData(currentTab.id, setContent)
  }, [])

  return (
    <div className={styles.Status} data-testid="Status">
      <h1>HTTP Status</h1>
      <MBCard cardClass={styles.card} cardTitle={statusLine}
              cardTooltip={""} cardValue={0} showPie={false} isBlur={false}
              customContent={(<a href={currentTab.url}>{content}</a>)}/>
    </div>
  );
}

export default Status;
