import React from 'react'

export class UserState {
  url?: string
  user?: string
  token?: string
  email?: string
  avatar?: string
  session?: any
  is_dark?: boolean
  is_pro?: boolean
  action?: string
  toolbar?: boolean
  da_mode?: boolean
  serp?: boolean
  places?: boolean
  dock?: string
  block?: string
  quota_max?: number
  quota_current?: number
  quota_k_max?: number
  quota_k_current?: number
  keyword?: string
  keywordhighlight?: boolean
  followed?: boolean
  nofollow?: boolean
  external?: boolean
  internal?: boolean
}

/**
 * Application state interface
 */
export interface AppState {
  data?: UserState,
  updateState: (newState: Partial<AppState>) => void
}

/**
 * Default application state
 */
const defaultState: AppState = {
  data: {
    url: '',
    user: '',
    token: '',
    email: '',
    avatar: '',
    session: '',
    is_dark: false,
    is_pro: false,
    action: '',
    toolbar: false,
    da_mode: false,
    serp: false,
    places: false,
    dock: 'top',
    block: '',
    quota_max: 0,
    quota_current: 0,
    quota_k_max: 0,
    quota_k_current: 0
  },
  updateState: (newState?: Partial<AppState>) => {},
}

/**
 * Creating the Application state context for the provider
 */
export const AppContext = React.createContext<AppState>(defaultState)