import React, { FC, useContext, useEffect, useState } from 'react'
import { LocalStorage } from '../../../helpers/LocalStorage'
import { AppContext } from '../../../config/state'
import styles from './MBQuota.module.scss';
import { MetaStorage } from '../../../helpers/MetaStorage'

interface MBQuotaProps {
  type?: string
}

const MBQuota: FC<MBQuotaProps> = (props) => {
  const {data} = useContext(AppContext)
  const [quota, setQuota] = useState<any>([])
  const ls = new LocalStorage()

  const updateQuota = () => {
    ls.get('config').then((res: any) => {
      if (props.type == 'keyword') {
        setQuota([
          res?.quota_k_max,
          res?.quota_k_current,
          res?.period_start,
          res?.period_reset,
        ])
      } else {
        setQuota([
          res?.quota_max,
          res?.quota_current,
          res?.period_start,
          res?.period_reset,
        ])
      }
    })
  }

  useEffect(() => {
    updateQuota()
    ls.storage().onChanged.addListener((changes, namespace) => {
      for (let [key, { oldValue, newValue }] of Object.entries(changes)) {
        switch(key) {
          case 'config':
            updateQuota()
            break
        }
      }
    });
  }, [])

  const QuotaMessage = () => {
    if (data?.is_pro || data?.token) {
      if (quota && quota[0] && quota[1] && quota[1]>0) {
        const meta = new MetaStorage()
        const [message, color] = meta.buildQuotaMessage(quota[1], quota[0], quota[3], data?.is_pro)
        if (color)
          return <p style={{color: color}}>{message}</p>
        else
          return <p>{message}</p>
      } else {
        return <></>
      }
    } else {
      return <></>
    }
  }

  return (
    <div className={styles.MBQuota}>
      <QuotaMessage/>
    </div>
  )
}

export default MBQuota;
