

class ApiHelper {
  /**
   * Get total factor numbers
   * @param data
   */
  factorsTotal(data: any) {
    return {
      helping: data.filter((item: any) => item.passed == true).length,
      hurting: data.filter((item: any) => item.passed == false).length
    }
  }

  /**
   * Get list of helping factors
   * @param data
   */
  factorsHelping(data: any) {
    const list: any[] = []
    data.forEach((item: any) => {
      if (item.passed == true) {
        list.push({
          level: item.level,
          name: item.issue_type ? item.issue_type.replaceAll('_', ' ') : '',
          details: '',
          expand: false,
          passed: item.passed
        })
      }
    })
    return list
  }

  /**
   * Get list of hurting factors
   * @param data
   */
  factorsHurting(data: any) {
    const list: any[] = []
    data.forEach((item: any) => {
      if (item.passed == false) {
        list.push({
          level: item.level,
          name: item.issue_type ? item.issue_type.replaceAll('_', ' ') : '',
          details: '',
          expand: false,
          passed: item.passed
        })
      }
    })
    return list
  }

}

export {ApiHelper}