import React, { FC, useContext, useState } from 'react'
import styles from './Ranking.module.scss'
import MBAlert from '../Common/MBAlert/MBAlert'
import { Button, FormControl, ListItemIcon, ListItemText, MenuItem, Select, Stack } from '@mui/material'
import Grid from '@mui/material/Unstable_Grid2'
import { getCurrentTab } from '../../api/browser'
import { ApiServiceV2, ApiServiceV2_Scope } from '../../api/api_v2'
import { AxiosError } from 'axios'
import { AppStorage } from '../../helpers/AppStorage'
import { AppContext } from '../../config/state'
import { Col, Row } from 'react-bootstrap'
import { Download } from '@mui/icons-material'
import { MetaStorage } from '../../helpers/MetaStorage'
import MBPremium from '../Common/MBPremium/MBPremium'
import { FlagIcon, FlagIconCode } from 'react-flag-kit'
import MBQuota from '../Common/MBQuota/MBQuota'
import MBErrorMessage from '../Common/MBErrorMessage/MBErrorMessage'

interface RankingProps {}

const resourceTabs = getCurrentTab()

const Ranking: FC<RankingProps> = () => {
  const metaStorage = new MetaStorage()
  const appStorage = new AppStorage()
  const {data, } = useContext(AppContext)
  const [error, setError] = useState('')
  const [currentTab] = resourceTabs.read()
  const [rankingOverview, updateRankingOverview] = useState(
    appStorage.getCoreTabJson('rankingOverview', currentTab.id)
  )

  let defaultDomain : string  = appStorage.getCoreTab('rankingDomain', currentTab.id)
  const [domain, setDomain] = useState(defaultDomain)
  const [domainErr, setDomainErr] = useState('')
  const domains = metaStorage.domains()
  const domainsData = []
  for(let f=0;f<domains.length;f++) {
    domainsData.push(
      <MenuItem value={domains[f].key.toLowerCase()}>{domains[f].name}</MenuItem>
    )
  }

  /**
   * Analyze provided keywords
   */
  const analyze = () => {
    // Set initial error values to empty
    let isErr = false
    setDomainErr('')

    // Check if the user has entered both fields correctly
    if ('' === domain) {
      setDomainErr('error-highlight')
      isErr = true
    }
    if (isErr) return

    appStorage.setCoreTab('rankingDomain', domain, currentTab.id)
    const service = new ApiServiceV2(data?.token)

    let url = currentTab.url
    if (domain == ApiServiceV2_Scope.Domain) {
      url = metaStorage.getDomain(url)
    } else if (domain == ApiServiceV2_Scope.Subdomain) {
      url = metaStorage.getDomain(url, true)
    }
    service.keywords_cache(url, domain).then( (res) => {
      setError('')
      updateRankingOverview(res)
      appStorage.setCoreTab('rankingOverview', JSON.stringify(res), currentTab.id)
    }, (err) => {
      setError(err)
      appStorage.setCoreTab('rankingOverview', JSON.stringify(''), currentTab.id)
    })
  }

  /**
   * Build keywords list
   */
  const keywords = []
  if (rankingOverview.length) {
    keywords.push(
      <Row className="mozbar-table-buttons">
        <Col xs={8}>
          <h1>Top 25 Results</h1>
        </Col>
        <Col xs={4} style={{textAlign: "right"}}>
          <Button variant="text" startIcon={<Download />}
                  onClick={(ev) =>
                  new MetaStorage().exportCSV(rankingOverview, 'Keyword,Page,Ranking,Difficulty,Monthly Volume', 'Ranking Keywords_'+currentTab.url)}>
            Export
          </Button>
        </Col>
      </Row>
    )
    keywords.push(
      <Row className="mozbar-table-header">
        <Col xs={6} style={{alignItems: "end"}}>
          Keyword
        </Col>
        <Col xs={2} style={{alignItems: "end"}}>
          Ranking
        </Col>
        <Col xs={2} style={{alignItems: "end"}}>
          Difficulty
        </Col>
        <Col xs={2}>
          Monthly Volume
        </Col>
      </Row>
    )
    let odd = true
    rankingOverview.forEach((item: any) => {
      keywords.push(
        <Row className={["mozbar-table-item", odd ? "mozbar-table-item-odd" : "" ].join(' ')}>
          <Col xs={6}>
            {item.keyword}
          </Col>
          <Col xs={2}>
            #{item.rank_position}
          </Col>
          <Col xs={2}>
            {item.difficulty}
          </Col>
          <Col xs={2}>
            {Math.round(item.volume)}
          </Col>
        </Row>
      )
      odd = !odd
    })
  }
  if (!keywords.length) keywords.push(<></>)

  /**
   * Main template
   */
  const disabled = !data?.is_pro
  return (
    <div className={styles.Ranking} data-testid="Ranking">
      <h1>Ranking Keywords <MBPremium/></h1>
      <MBAlert href={"https://moz.com/products/pro/pricing?utm_source=mozbar_v4&utm_medium=mozbar&utm_campaign=premium_new_signup&utm_content=ranking-keywords"}
               message={(<><strong>Get Mozbar Premium</strong> Available with Moz Pro</>)} button={"Sign Up"}
               href_token={"https://moz.com/products/pro/pricing?utm_source=mozbar_v4&utm_medium=mozbar&utm_campaign=premium_new_signup&utm_content=ranking-keywords"}
               message_token={(<><strong>Get Mozbar Premium</strong> Available with Moz Pro</>)} button_token={"Upgrade"}/>
      <p>Research by site to identify top ranking keywords and gain competitive insights.</p>
      {error && (<MBErrorMessage message={error}/>)}
      <Grid container spacing={2} className={styles.gridContainer}>
        <Grid xs={4} justifyContent="center" alignItems="center">
          <div className={'inputContainer'}>
            <div className={["input-label", domainErr].join(' ')}>Explore by</div>
            <FormControl size={"small"} fullWidth>
              <Select
                value={domain}
                displayEmpty={false}
                inputProps={{ 'aria-label': 'Without label' }}
                onChange={(ev: any) => setDomain(ev.target.value)}
              >
                {domainsData}
              </Select>
            </FormControl>
          </div>
        </Grid>
        <Grid xs={3} justifyContent="center" alignItems="center">
          <div className={"button-section-grid"}>
            <Button variant="contained" onClick={analyze} size="small" fullWidth disabled={disabled}>Analyze</Button>
          </div>
        </Grid>
        <Grid xs={5}></Grid>
      </Grid>
      <MBQuota type={"keyword"}/>
      {data?.is_pro && (
        <div className="mozbar-table-main">
          {keywords}
        </div>
      )}
    </div>
  )
}

export default Ranking
