import React, { FC } from 'react';
import { Card, CardContent, CardHeader } from '@mui/material'
import { Col, Row } from 'react-bootstrap'
import MBPie from '../MBPie/MBPie'
import { MetaStorage } from '../../../helpers/MetaStorage'
// import { ReactJSXElement } from '@emotion/react/types/jsx-namespace'
import MBTooltip from '../MBTooltip/MBTooltip'
import { EventStorage } from '../../../helpers/EventStorage'

interface MBCardProps {
  cardClass: string
  cardTitle: string
  cardTooltip: string
  cardValue: number | null
  showPie: boolean
  isBlur: boolean
  customContent?: JSX.Element
  url?: string
}

const MBCard: FC<MBCardProps> = (props) => {
  const metaStorage = new MetaStorage()

  const renderBlur = (value: number | undefined | null, isBlur: boolean, url?: string) => {
    const textClick = () => {
      const event = new EventStorage()
      if (url) {
        event.openLink(url)
      }
    }

    if (!isBlur) {
      return (
        <h1 className="card-text main-cursor" onClick={textClick}>
          {metaStorage.numberFormat(value)}
        </h1>
      )
    } else {
      return (
        <h1 className="card-text" style={{ filter: 'blur(8px)', pointerEvents: 'none' }}>
          lorem
        </h1>
      )
    }
  }

  let isCustomContent = props.customContent ? true : false
  const customData = []
  if (isCustomContent) {
    if (Array.isArray(props.customContent?.props?.children) && typeof props.customContent?.props?.children[0] === 'string') {
      props.customContent?.props?.children.forEach((item: any) => {
        customData.push(<div>{item}</div>)
      })
    } else {
      customData.push(<div>{props.customContent}</div>)
    }
  }

  return (
    <Card className={props.cardClass}>
      <CardHeader title={props.cardTitle}
                  action={props.cardTooltip &&
                    (<MBTooltip title={props.cardTooltip} placement={"top"}><span className="material-symbols-outlined">info</span></MBTooltip>)
                  }
      />
      <CardContent sx={{ fontSize: '0.75em' }}>
        {isCustomContent && (
          <>{customData}</>
        )}
        {!isCustomContent && props.showPie && (
          <Row>
            <Col xs={5}>
              <MBPie size={30} value={props.cardValue} url={props.url}/>
            </Col>
            <Col xs={7}>
              {renderBlur(props.cardValue, props.isBlur, props.url)}
            </Col>
          </Row>
        )}
        {!isCustomContent && !props.showPie && (
          <Row>
            <Col xs={12}>
              {renderBlur(props.cardValue, props.isBlur, props.url)}
            </Col>
          </Row>
        )}
      </CardContent>
    </Card>
  )
};

export default MBCard;
