import React, { FC, useState } from 'react'
import styles from './MBFactors.module.scss';
import { CheckCircleOutline, Error, WarningAmber } from '@mui/icons-material'
import { ListItem, ListItemIcon, ListItemText } from '@mui/material'

interface MBFactorsProps {
  factors: any[]
  type: string
}

const MBFactors: FC<MBFactorsProps> = (props) => {
  const [expands, setExpands] = useState<any>(props.factors ? props.factors.map((item) => item.expand) : [])
  const [render, setRender] = useState<any>(false)

  const data = []

  const handleClick = (index: number) => {
    expands[index] = !expands[index]
    setExpands(expands)
    setRender(!render)
  }

  const handleExpand = () => {
    setExpands(expands.map((item: boolean) => !item))
    setRender(!render)
  }

  data.push(
    <div className={styles.padding}>
      {props.type}
    </div>
  )
  if (props.factors) {
    props.factors.forEach((item, index) => {
      let icon = undefined
      if (item.passed) {
        icon = <CheckCircleOutline className={styles.success}/>
      } else {
        switch (item.level) {
          case 'error':
            icon = <Error className={styles.error}/>
            break
          case 'warning':
            icon = <WarningAmber className={styles.warning}/>
            break
          case 'success':
            icon = <CheckCircleOutline className={styles.success}/>
            break
        }
      }

      data.push(
        <>
          <ListItem divider={false}>
            <ListItemIcon>
              {icon}
            </ListItemIcon>
            <ListItemText primary={item.name} sx={{ textDecoration: 'none' }}/>
          </ListItem>
        </>
      )
    })
  }

  return (
    <div className={styles.MBFactors}>
      {data}
    </div>
  );
}

export default MBFactors;
