import React, { FC, useContext } from 'react'
import styles from './MBPremium.module.scss';
import { AppStorage } from '../../../helpers/AppStorage'
import { Chip } from '@mui/material'
import { Lock } from '@mui/icons-material'
import { AppContext } from '../../../config/state'

interface MBPremiumProps {}

const MBPremium: FC<MBPremiumProps> = () => {
  const {data, } = useContext(AppContext)

  if (!data?.is_pro) {
    const chipStyle = {borderRadius: "15px", color: "#000000", fontSize: "13px"}

    return (
      <span className={styles.MBPremium}>
        <Chip label="Premium"
              icon={<Lock style={{fontSize: "20px", color: "#000000", paddingLeft: "4px"}}/>}
              sx={{ ...chipStyle, background: "#FFD05F" }}/>
      </span>
    )
  } else {
    return (<></>)
  }
}

export default MBPremium;
