import React, { FC, useEffect, useState } from 'react'
import styles from './PageElements.module.scss';
import { getCurrentTab } from '../../api/browser'
import { EventStorage } from '../../helpers/EventStorage'
import MBBox from '../Common/MBBox/MBBox'

const resourceTabs = getCurrentTab()

const PageElements: FC = () => {
  const eventStorage = new EventStorage()

  const [currentTab] = resourceTabs.read()
  const url = currentTab?.url
  const title = currentTab?.title

  const [keywords, setKeywords] = useState('')
  const [description, setDescription] = useState('')
  const [h1, setH1] = useState([])
  const [h2, setH2] = useState([])
  const [img, setImg] = useState([])

  useEffect( () => {
    /**
     * Request data from the web page
     */
    eventStorage.sendTabMessage(currentTab.id,
      eventStorage.buildMessage(eventStorage.SOURCE_CONTENT, eventStorage.SOURCE_EXTENSION, "pageinfo", {})
    )

    chrome.runtime.onMessage.addListener(response => {
      if (response.type === eventStorage.SOURCE_EXTENSION) {
        switch (response.message) {
          case 'pageinfo':
            if (response.keywords)
              setKeywords(response.keywords[0])
            if (response.description)
              setDescription(response.description[0])
            if (response.h1)
              setH1(response.h1)
            if (response.h2)
              setH2(response.h2)
            if (response.img)
              setImg(response.img)
            break
        }
      }
    })
  }, [])

  const stripHtml = (html: string) => {
    let tmp = document.createElement("DIV");
    tmp.innerHTML = html;
    return tmp.textContent || tmp.innerText || "";
  }

  const items = [
    {
      name: 'URL',
      secondary: url.length ? url.length + ' characters' : '',
      content: url.length ? (<a onClick={(ev) => eventStorage.openLink(url)}>
        {url.length>60 ? url.substring(0,60) + '...' : url}
      </a>) : 'Not found',
      copy: false
    },
    {
      name: 'Page Title',
      secondary: title.length ? title.length + ' characters' : '',
      content: title.length ? title : 'Not found',
      copy: false
    },
    {
      name: 'Meta Description',
      secondary: description && description.length ? description.length + ' characters' : '',
      content: description ? description : 'Not found',
      copy: true
    },
    {
      name: 'Meta Keywords',
      secondary: keywords && keywords.length ? keywords.length + ' characters' : '',
      content: keywords ? keywords : 'Not found',
      copy: true
    },
    {
      name: 'H1',
      secondary: '',
      content: h1.length ? h1.map((val) => (<div>{stripHtml(val)}</div>)) : 'Not found',
      copy: true
    },
    {
      name: 'H2',
      secondary: '',
      content: h2.length ? h2.map((val) => (<div>{stripHtml(val)}</div>)) : 'Not found',
      copy: true
    },
    {
      name: 'Images Alt Text',
      secondary: '',
      content: img.length ? img.map((val) => (<div>{val}</div>)) : 'Not found',
      copy: true
    }
  ]

  const content = []
  for(const key in items) {
    const item = items[key]
    content.push(
      <MBBox item={item} copy={item.copy}/>
    )
  }

  return (
    <div className={styles.PageElements} data-testid="PageElements">
      <h1>On-Page Elements</h1>
      {content}
    </div>
  )
}

export default PageElements
