import React, { FC, useEffect, useState } from 'react'
import styles from './Attributes.module.scss';
import { getCurrentTab } from '../../api/browser'
import { Col, Row } from 'react-bootstrap'
import { storage } from 'webextension-polyfill'
import { TabStorage } from '../../helpers/TabStorage'
import { EventStorage } from '../../helpers/EventStorage'
import { MetaStorage } from '../../helpers/MetaStorage'
import MBBox from '../Common/MBBox/MBBox'

interface AttributesProps {}

const resourceTabs = getCurrentTab()

const Attributes: FC<AttributesProps> = () => {
  const metaStorage = new MetaStorage()

  const [pageLoad, setPageLoad] = useState('-')
  const [canonical, setCanonical] = useState([])
  const [hreflangs, setHreflangs] = useState([])
  const [robots, setRobots] = useState([])
  const [robotsurl, setRobotsurl] = useState('')
  const [robotsmeta, setRobotsmeta] = useState('')
  const [sitemap, setSitemap] = useState([])
  const tabStorage = new TabStorage()

  const tabs = resourceTabs.read()
  const currentTab = tabs[0]

  useEffect(() => {
    /**
     * Request data from the web page
     */
    const event = new EventStorage()
    event.sendTabMessage(currentTab.id,
      event.buildMessage(event.SOURCE_CONTENT, event.SOURCE_EXTENSION, "pageinfo", {})
    );

    chrome.runtime.onMessage.addListener(response => {
      if (response.type == event.SOURCE_EXTENSION) {
        switch (response.message) {
          case 'pageinfo':
            if (response.canonical)
              setCanonical(response.canonical)
            if (response.robots)
              setRobots(response.robots)
            if (response.robotsurl)
              setRobotsurl(response.robotsurl)
            if (response.hreflangs)
              setHreflangs(response.hreflangs)
            if (response.sitemaps)
              setSitemap(response.sitemaps)
            break
        }
      }
    })

    tabStorage.getPageLoadTime(currentTab.id, setPageLoad)
  }, [])

  const cacheUrl = metaStorage.buildGoogleCacheUrl(currentTab?.url)
  const items = [
    {
      name: 'Canonical URL',
      secondary: '',
      content: canonical.length ? canonical.map((val) => (
        <a onClick={(ev) => new EventStorage().openLink(val)}>{val}</a>
      )) : 'Not found',
      copy: canonical.length ? true : false,
      copyText: canonical,
    },
    {
      name: 'Page Load Time',
      secondary: '',
      content: pageLoad,
      copy: false,
    },
    {
      name: 'Google Cache URL',
      secondary: '',
      content: (<a onClick={(ev) => new EventStorage().openLink(cacheUrl)}>
        {cacheUrl.length>60 ? cacheUrl.substring(0,60) + '...' : cacheUrl}
      </a>),
      copyText: cacheUrl,
      copy: true,
    },
    {
      name: 'Hreflangs',
      secondary: '',
      content: hreflangs.length ? hreflangs.map((val: any) => (
        <div><strong>{val.hreflang}</strong>: {val.href}</div>
      )) : 'Not found',
      copy: hreflangs.length ? true : false,
      copyText: hreflangs,
    },
    {
      name: 'Sitemap',
      secondary: '',
      content: sitemap.length ? sitemap.map((val: string) => (
        <div><a onClick={(ev) => new EventStorage().openLink(val)}>{val}</a></div>
      )) : 'Not found',
      copy: sitemap.length ? true : false,
      copyText: sitemap,
    },
    {
      name: 'Robots.txt',
      secondary: '',
      content: robotsurl.length ? (<>
        {robotsmeta && (<div><strong>Meta</strong>: {robotsmeta}</div>)}
        <div><strong>URL</strong>: <a onClick={(ev) => new EventStorage().openLink(robotsurl)}>{robotsurl}</a></div>
      </>
      ) : 'Not found',
      copy: robotsurl.length ? true : false,
      copyText: robotsurl,
    },
  ]

  const content = []
  for(const key in items) {
    const item = items[key]
    content.push(
      <MBBox item={item} copy={item.copy} />
    )
  }

  return (
    <div className={styles.Attributes} data-testid="Attributes">
      <h1>General Attributes</h1>
      {content}
    </div>
  )
};

export default Attributes;
