import React, { Suspense, useContext, useEffect } from 'react'
import 'bootstrap/dist/css/bootstrap.min.css';
import './App.css';
import { Row, Col }
  from 'react-bootstrap';
import { AppContext } from '../config/state'
import { NavLink, Route, Routes, useLocation, useNavigate } from 'react-router-dom'
import Home from '../components/Home/Home'
import Metrics from '../components/Metrics/Metrics'
import Login from '../components/Login/Login'
import Feedback from '../components/Feedback/Feedback'
import PageElements from '../components/PageElements/PageElements'
import Attributes from '../components/Attributes/Attributes'
import Markup from '../components/Markup/Markup'
import Status from '../components/Status/Status'
import Brand from '../components/Brand/Brand'
import Links from '../components/Links/Links'
import Settings from '../components/Settings/Settings'
import Loader from '../components/Loader/Loader'
import { AppStorage } from '../helpers/AppStorage'
import {
  Avatar,
  Collapse, createTheme,
  List,
  ListItemButton,
  ListItemText, Stack,
  ThemeProvider
} from '@mui/material'
import { ExpandMore, ExpandLess, OpenInNew } from '@mui/icons-material'
import AddProfile from '../components/AddProfile/AddProfile'
import DomainOverview from '../components/DomainOverview/DomainOverview'
import Content from '../components/Content/Content'
import Helping from '../components/Helping/Helping'
import Hurting from '../components/Hurting/Hurting'
import Summary from '../components/Summary/Summary'
import Ranking from '../components/Ranking/Ranking'
import { EventStorage } from '../helpers/EventStorage'
import MBNew from '../components/Common/MBNew/MBNew'
import { getCurrentTab } from '../api/browser'
import { storage } from 'webextension-polyfill'
import { LocalStorage } from '../helpers/LocalStorage'

const resourceTabs = getCurrentTab()

function App() {
  const app = new AppStorage()
  const location = useLocation()
  const navigate = useNavigate()
  const [currentTab] = resourceTabs.read()

  const {data, updateState} = useContext(AppContext)

  const [expandIndex, setExpandIndex] =
    React.useState(app.getCore('expandindex'));

  /**
   * Extension first open
   */
  useEffect(() => {
    /**
     * Main event cycle
     */
    const ls = new LocalStorage()
    ls.storage().onChanged.addListener((changes) => {
      for (let [key, { oldValue, newValue }] of Object.entries(changes)) {
        switch(key) {
          case 'config':
            const newState = {data: {
                ...data,
                is_pro: newValue?.is_pro,
                is_dark: newValue?.theme,
                dock: newValue?.dock,
                token: newValue?.token,
                serp: newValue?.serp,
                places: newValue?.places,
                toolbar: newValue?.toolbar,
                da_mode: newValue?.da_mode,
                user: newValue?.user,
                avatar: newValue?.avatar,
                block: newValue?.block,
            }}
            updateState(newState)
            break
        }
      }
    });

    storage.local.get('session').then(item => {
      if (!data?.token && item.session) {
        const token = item.session
        updateState(app.prepareState(data, 'token', token))
        app.userLookup(data, updateState, token, currentTab)
        item = {session: ''}
        storage.local.set(item)
      }
    });

    // Navigate to previously opened url
    const url = app.getCore('url')
    if (url) navigate(url)
  }, [])


  /**
   * Remember location change
   */
  useEffect(() => {
    const url = app.getCore('url')
    if (url !== location.pathname) {
      app.setCore('url', location.pathname)
    }
  }, [location]);


  /**
   * General font styles
   */
  const theme = createTheme({
    typography: {
      fontSize: 12,
      fontFamily: '"Lato", sans-serif'
    },
    components: {
      MuiSwitch: {
        styleOverrides: {
          switchBase: {
            color: "var(--switch-off-color)",
            "&.Mui-checked": {
              color: "var(--switch-color)"
            }
          },
          colorPrimary: {
            color: "var(--switch-off-color)",
            "&.Mui-checked": {
              color: "var(--switch-color)"
            }
          },
          track: {
            opacity: 1,
            backgroundColor: "var(--switch-off-line-color)",
            ".Mui-checked.Mui-checked + &": {
              opacity: 1,
              backgroundColor: "var(--switch-line-color)"
            }
          }
        }
      },
      MuiCheckbox: {
        styleOverrides: {
          root: {
            color: "var(--switch-color)"
          },
          checked: {
            color: "var(--switch-color)"
          },
          colorPrimary: {
            "&.Mui-checked": {
              color: "var(--switch-color)"
            }
          },
        }
      }
    }
  });

  /**
   * Handle click on menu items
   * @param item
   */
  const handleClick = (item: any) => {
    if (item.url && item.url.search('https://') !== -1) {
      new EventStorage().openLink(item.url)
    }
    if (item.expand !== undefined) {
      if (expandIndex === item.expand) {
        setExpandIndex('-1')
        app.setCore('expandindex', '-1')
      } else {
        setExpandIndex(item.expand)
        app.setCore('expandindex', item.expand)
      }
    }
  };

  /**
   * Get prope title for login menu item
   * @param user
   * @param avatar
   */
  const loginTitle = (user: string | undefined, avatar: string | undefined) => {
    if (!user)
      return ('Login')

    if (avatar) {
      return <Stack direction="row" spacing={1}><Avatar src={avatar} sx={{ width: 24, height: 24 }}/><span>{user}</span></Stack>
    } else {
      return <></>
    }
  }

  /**
   * All menu items
   */
  const menuItems = [
    {
      name: 'Page Analysis',
      url: '',
      expand: 0,
      index: 0,
      class: 'menu-item',
      children: [
        {
          name: 'Link Metrics',
          url: '/metrics',
          index: 1,
          class: 'menu-item-light',
        },
        {
          name: 'General Attributes',
          url: '/attributes',
          index: 2,
          class: 'menu-item-light',
        },
        {
          name: 'On-Page Elements',
          url: '/onpage',
          index: 3,
          class: 'menu-item-light',
        },
        {
          name: 'Markup',
          url: '/markup',
          index: 4,
          class: 'menu-item-light',
        },
        {
          name: 'HTTP Status',
          url: '/status',
          index: 5,
          class: 'menu-item-light',
        }
      ]
    },
    {
      name: 'Domain Overview',
      url: '/domain',
      new: true,
      index: 6,
      class: 'menu-item',
    },
    {
      name: 'Ranking Keywords',
      url: '/ranking',
      new: true,
      index: 7,
      class: 'menu-item',
    },
    {
      name: 'Highlight Links',
      url: '/links',
      index: 8,
      class: 'menu-item',
    },
    {
      name: 'Page Optimization',
      url: '/onpage',
      expand: 1,
      index: 9,
      class: 'menu-item',
      children: [
        {
          name: 'On-Page Grader',
          url: '/summary',
          index: 10,
          class: 'menu-item-light',
        },
        {
          name: 'Hurting Factors',
          url: '/hurting',
          index: 11,
          class: 'menu-item-light',
        },
        {
          name: 'Helping Factors',
          url: '/helping',
          index: 12,
          class: 'menu-item-light',
        },
      ]
    },
  ]

  const menuItemsBottom = [
    {
      name: 'MozBar Home',
      url: '/home',
      index: 14,
      bottom: true,
      class: 'menu-item-light-nopad',
    },
    {
      name: 'Settings',
      url: '/settings',
      index: 15,
      bottom: true,
      class: 'menu-item-light-nopad',
    },
    {
      name: loginTitle(data?.token ? data?.user : '', data?.token ?'https:' + data?.avatar : ''),
      url: '/login',
      index: 16,
      bottom: true,
      class: 'menu-item-account',
    },
    {
      name: 'Send us feedback',
      url: 'https://moz.com/help/contact-mozbar',
      index: 17,
      bottom: true,
      class: 'menu-item-feedback',
    }
  ]

  /**
   * Render single menu item
   * @param item
   * @param padding
   */
  const renderItem = (item: any, padding: number = 0) => {
    let classText = ''
    if (item.classText) classText = item.classText
    let showIcon
    if (item.showIcon) showIcon = <OpenInNew sx={{marginRight: "10px"}}/>
    let showNew
    if (item.new) showNew = <MBNew/>

    if (item.children) {
      return (
        <>
          <ListItemButton sx={{ pl: padding }}
                          className={item.class}
                          onClick={(e) => handleClick(item)}
                          divider={true}>
            <ListItemText primary={item.name} sx={{ textDecoration: 'none' }} className={classText}/>
            {showIcon}
            {expandIndex == item.expand ? <ExpandLess/> : <ExpandMore/>}
          </ListItemButton>
          <Collapse in={expandIndex == item.expand} timeout="auto" unmountOnExit>
            <List component="div" disablePadding>
              {
                item.children.map((value: any, index: number) => renderItem(value, padding + 4))
              }
            </List>
          </Collapse>
        </>
      )
    }
    if (item.url) {
      return (
        <NavLink to={item.url} style={{ textDecoration: 'none' }}>
          <ListItemButton sx={{ pl: padding }}
                        className={item.class}
                        onClick={(e) => handleClick(item)}
                        selected={location.pathname == item.url}
                        divider={true}>
            <ListItemText primary={item.name} sx={{ textDecoration: 'none' }} className={classText}/>
            {showIcon} {showNew}
          </ListItemButton>
        </NavLink>
      )
    }

    return (
      <ListItemButton sx={{ pl: padding }}
                      className={item.class}
                      onClick={(e) => handleClick(item)}
                      selected={location.pathname == item.url}
                      divider={true}>
        <ListItemText primary={item.name} sx={{ textDecoration: 'none' }} className={classText}/>
        {showIcon} {showNew}
      </ListItemButton>
    )
  }

  const renderMenu = (
    <List component="nav" className="menu-content-top" sx={{ pb: 0 }}>
      {
        menuItems.map((value, index) => renderItem(value, 0))
      }
    </List>
  );
  const renderMenuBottom = (
    <List component="nav" className="menu-content-bottom" sx={{ pb: 0 }}>
      {
        menuItemsBottom.map((value, index) => renderItem(value, 0))
      }
    </List>
  );

  return (
    <ThemeProvider theme={theme}>
      <div className={data?.is_dark ? 'theme-dark' : 'theme-light'}>
          <Row className={["mozbar-row"].join(' ')}>
            <Col xs={4} className="menu-content">
              <div className="menu-logo">
                <NavLink to={"/"} style={{ textDecoration: 'none' }}><img src={'images/logo_blue.png'}/></NavLink>
              </div>
              {renderMenu}
              {renderMenuBottom}
            </Col>
            <Col xs={8} className="mozbar-col">
              <div className="main-content">
                <div className="submain-content">
                  <Suspense fallback={<Loader/>}>
                    <Routes>
                      <Route index element={<Settings/>}/>
                      <Route path="/" element={<Home/>}/>
                      <Route path="/onpage" element={<PageElements/>}/>
                      <Route path="/attributes" element={<Attributes/>}/>
                      <Route path="/metrics" element={<Metrics />}/>
                      <Route path="/markup" element={<Markup/>}/>
                      <Route path="/status" element={<Status/>}/>
                      <Route path="/brand" element={<Brand/>}/>
                      <Route path="/links" element={<Links/>}/>
                      <Route path="/login" element={<Login/>}/>
                      <Route path="/feedback" element={<Feedback/>}/>
                      <Route path="/settings" element={<Settings/>}/>
                      <Route path="/addprofile" element={<AddProfile/>}/>
                      <Route path="/addprofile/:id" element={<AddProfile/>}/>
                      <Route path="/domain" element={<DomainOverview/>}/>
                      <Route path="/summary" element={<Summary/>}/>
                      <Route path="/hurting" element={<Hurting/>}/>
                      <Route path="/helping" element={<Helping/>}/>
                      <Route path="/content" element={<Content/>}/>
                      <Route path="/ranking" element={<Ranking/>}/>
                      <Route path="*" element={<Home/>}/>
                    </Routes>
                  </Suspense>
                </div>
              </div>
            </Col>
          </Row>
      </div>
    </ThemeProvider>
  );
}

export default App;
