import React, { FC, useContext } from 'react'
import { WarningAmber } from '@mui/icons-material'
import { Alert, Button } from '@mui/material'
import { EventStorage } from '../../../helpers/EventStorage'
import { AppContext } from '../../../config/state'
import { MetaStorage } from '../../../helpers/MetaStorage'

interface MBAlertProps {
  href?: string
  message?: any
  button?: string
  href_token?: string
  message_token?: any
  button_token?: string
}

const MBAlert: FC<MBAlertProps> = (props) => {
  const meta = new MetaStorage()
  const {data, } = useContext(AppContext)

  const button = () => {
    if (data?.token)
      if (props.button_token)
        return props.button_token
      else
        return 'Upgrade'
    else
      if (props.button)
        return props.button
      else
        return 'Create'
  }

  const upgrade = () => {
    if (props.href || props.href_token) {
      if (data?.token)
        new EventStorage().openLink(props.href_token)
      else
        new EventStorage().openLink(props.href)
    } else if (data?.token) {
      new EventStorage().openLink(meta.metrics_page_url_upgrade)
    } else {
      new EventStorage().openLink(meta.metrics_page_url_create)
    }
  }

  const message = () => {
    if (props.message || props.message_token) {
      if (!data?.token) {
        return (
          <span style={{ fontSize: "14px" }}>{props.message}</span>
        )
      } else {
        return (
          <span style={{ fontSize: "14px" }}>{props.message_token}</span>
        )
      }
    } else {
      if (!data?.token) {
        return (
          <span style={{ fontSize: "14px" }}><strong>Get Link Metrics</strong> with a FREE Moz Community Account</span>
        )
      } else {
        return (
          <span style={{ fontSize: "14px" }}><strong>Unlock MozBar Premium</strong> to access more metrics</span>
        )
      }
    }
  }

  if (!data?.is_pro) {
    return (
      <Alert
        sx={{marginBottom: "15px"}}
        action={
          <Button color="inherit" size="small"
                  onClick={() => {upgrade()}}
                  sx={{textTransform: "none", fontWeight: "700", fontSize: "14px", textDecoration: "underline", textWrap: "nowrap"}}>
            {button()}
          </Button>
        }
        icon={<WarningAmber/>} severity={'warning'}
      >
        {message()}
      </Alert>
    )
  } else {
    return (<></>)
  }
}

export default MBAlert;
